const exam1Questions = [
  // BIOLOGY - BOTANY (1-45)
  { id: 1, subject: "Biology", section: "Botany", q: "In the Calvin cycle (C3 pathway), the first stable product of CO₂ fixation is:", options: ["Oxaloacetate (OAA)", "3-Phosphoglycerate (3-PGA)", "Glyceraldehyde-3-phosphate (G3P)", "Ribulose-1,5-bisphosphate (RuBP)"], ans: 1, exp: "CO₂ combines with RuBP (5C) via RuBisCO enzyme → unstable 6C compound → 2 molecules of 3-PGA (3C). 3-PGA is the first STABLE product in C3 plants. In C4 plants, OAA is the first stable product. NCERT Class 11, Ch 13.", stars: 5 },
  { id: 2, subject: "Biology", section: "Botany", q: "Kranz anatomy is a characteristic structural feature of:", options: ["C3 plants", "CAM plants", "C4 plants", "Hydrophytes"], ans: 2, exp: "Kranz anatomy in C4 plants: mesophyll cells surrounding bundle sheath cells in a wreath-like arrangement. Bundle sheath cells have large chloroplasts (without grana) where Calvin cycle occurs. Examples: Sugarcane, Maize. NCERT Class 11, Ch 13.", stars: 5 },
  { id: 3, subject: "Biology", section: "Botany", q: "Which of the following is a macro-element essential for plants but is a component of chlorophyll?", options: ["Iron (Fe)", "Zinc (Zn)", "Magnesium (Mg)", "Molybdenum (Mo)"], ans: 2, exp: "Magnesium (Mg) is a macro-element (required in large amounts) and is the central atom of the chlorophyll molecule (porphyrin ring). Also activates many enzymes. Fe is a micro-element involved in chlorophyll synthesis. NCERT Class 11, Ch 12.", stars: 5 },
  { id: 4, subject: "Biology", section: "Botany", q: "Abscisic acid (ABA) promotes all of the following EXCEPT:", options: ["Stomatal closure", "Seed dormancy", "Leaf senescence", "Stem elongation"], ans: 3, exp: "ABA functions: (1) closes stomata during water stress, (2) promotes seed dormancy, (3) promotes leaf senescence and abscission, (4) inhibits germination. Stem elongation is promoted by GIBBERELLINS (GA₃), NOT ABA. NCERT Class 11, Ch 15.", stars: 5 },
  { id: 5, subject: "Biology", section: "Botany", q: "In nitrogen fixation by Rhizobium, the enzyme nitrogenase is protected from oxygen by:", options: ["Nitrate reductase", "Leghemoglobin", "Ferredoxin", "Nitrogenase reductase"], ans: 1, exp: "Leghemoglobin (a pink pigment) is present in root nodules and acts as an O₂ scavenger — it keeps the nodule micro-aerobic, protecting nitrogenase (which is irreversibly inactivated by O₂). It gives root nodules their pink/red colour. NCERT Class 11, Ch 12.", stars: 5 },
  { id: 6, subject: "Biology", section: "Botany", q: "The net gain of ATP molecules per glucose in glycolysis (cytoplasm only) is:", options: ["38", "8", "2", "4"], ans: 2, exp: "Glycolysis: Glucose → 2 Pyruvate. Investment phase: 2 ATP used. Pay-off phase: 4 ATP produced. Net gain = 4 − 2 = 2 ATP + 2 NADH. (Total aerobic = 36–38 ATP but glycolysis alone = 2 ATP net). NCERT Class 11, Ch 14.", stars: 4 },
  { id: 7, subject: "Biology", section: "Botany", q: "Photorespiration occurs in C3 plants when RuBisCO acts on:", options: ["CO₂ (carboxylation)", "O₂ (oxygenation)", "H₂O", "NADPH"], ans: 1, exp: "Photorespiration: At high O₂/low CO₂ conditions, RuBisCO uses O₂ instead of CO₂ → RuBP + O₂ → phosphoglycolate (2C) + 3-PGA. Phosphoglycolate is a wasteful product. C4 plants avoid photorespiration by concentrating CO₂ in bundle sheath via PEP carboxylase. NCERT Class 11, Ch 13.", stars: 4 },
  { id: 8, subject: "Biology", section: "Botany", q: "Which of the following is NOT correctly matched?", options: ["Auxin — promotes cell elongation", "Cytokinin — delays leaf senescence", "Ethylene — promotes fruit ripening", "Gibberellin — promotes root initiation"], ans: 3, exp: "Gibberellin promotes stem elongation, flowering in LDP, breaking dormancy, parthenocarpy — NOT root initiation. Root initiation (adventitious roots) is promoted by AUXIN (IAA). NCERT Class 11, Ch 15.", stars: 5 },
  { id: 9, subject: "Biology", section: "Botany", q: "Totipotency was first demonstrated using:", options: ["Pollen grains", "Single leaf cells of tobacco", "Carrot phloem parenchyma cells", "Onion root tip cells"], ans: 2, exp: "F.C. Steward (1950s) demonstrated totipotency by culturing carrot phloem parenchyma cells → callus → complete carrot plant on appropriate media (auxin + cytokinin). This formed the basis of plant tissue culture. NCERT Class 11, Ch 15.", stars: 5 },
  { id: 10, subject: "Biology", section: "Botany", q: "In angiosperms, double fertilization results in formation of:", options: ["Seed and fruit", "Zygote (2n) and primary endosperm nucleus (3n)", "Two zygotes", "Endosperm (2n) and embryo (3n)"], ans: 1, exp: "Double fertilization (unique to angiosperms): One male gamete (n) + egg cell (n) → zygote (2n) → embryo. Second male gamete (n) + 2 polar nuclei (n+n) → primary endosperm nucleus (3n, triploid) → endosperm. NCERT Class 12, Ch 2.", stars: 5 },
  { id: 11, subject: "Biology", section: "Botany", q: "The phenomenon of apomixis in plants refers to:", options: ["Vegetative propagation", "Formation of seeds without fertilization", "Cross pollination", "Germination of seeds in darkness"], ans: 1, exp: "Apomixis: formation of seeds (embryo) without fertilization. Types: (1) Agamospermy — embryo from unfertilized egg, (2) Vegetative apomixis — bulbils, etc. Advantage: preserves superior hybrid traits. Used in agriculture to maintain hybrid vigor. NCERT Class 12, Ch 2.", stars: 4 },
  { id: 12, subject: "Biology", section: "Botany", q: "The gametophyte in angiosperms is represented by:", options: ["Pollen grain and embryo sac", "Ovule and anther", "Seed and fruit", "Stem and leaf"], ans: 0, exp: "Alternation of generations: Sporophyte (2n, dominant in angiosperms) produces spores → gametophyte (n, reduced). Male gametophyte = mature pollen grain (3-celled). Female gametophyte = embryo sac (8-nucleate, 7-celled). NCERT Class 12, Ch 2.", stars: 4 },
  { id: 13, subject: "Biology", section: "Botany", q: "Water potential (Ψw) is expressed as:", options: ["Ψw = Ψs + Ψp", "Ψw = Ψs − Ψp", "Ψw = Ψp − Ψs", "Ψw = Ψs × Ψp"], ans: 0, exp: "Water potential: Ψw = Ψs (solute/osmotic potential, always negative) + Ψp (pressure potential, can be positive or negative). Pure water: Ψw = 0. NCERT Class 11, Ch 11.", stars: 5 },
  { id: 14, subject: "Biology", section: "Botany", q: "Companion cells are associated with which vascular tissue and help in:", options: ["Xylem; water transport", "Phloem; loading and unloading of sugars", "Xylem; mineral transport", "Phloem; water storage"], ans: 1, exp: "Companion cells (in phloem) have dense cytoplasm and many mitochondria. They assist sieve tube elements (which lack nucleus) by: (1) loading sucrose into sieve tubes from mesophyll (source), (2) unloading at sink tissue. NCERT Class 11, Ch 6.", stars: 4 },
  { id: 15, subject: "Biology", section: "Botany", q: "In Mendelian genetics, the principle of dominance states that:", options: ["Both alleles are equally expressed in F1", "In F1, only one allele (dominant) is expressed; the other (recessive) is masked", "Both traits blend in F1", "Each trait is controlled by two genes"], ans: 1, exp: "Mendel's 1st Law (Principle of Dominance): When two plants with contrasting characters are crossed, only one character (dominant) appears in F1. The other (recessive) is masked but not lost — it reappears in F2 in 1/4 progeny. NCERT Class 12, Ch 5.", stars: 4 },
  { id: 16, subject: "Biology", section: "Botany", q: "Transpiration pull (cohesion-tension theory) for ascent of sap was proposed by:", options: ["Dixon & Joly", "Munch", "Priestley", "Strasburger"], ans: 0, exp: "Dixon & Joly (1894) proposed the Cohesion-Tension theory: (1) Cohesion of water molecules (H-bonding), (2) Adhesion to xylem walls, (3) Transpiration pull creates tension. Munch proposed pressure flow hypothesis for phloem transport. NCERT Class 11, Ch 11.", stars: 4 },
  { id: 17, subject: "Biology", section: "Botany", q: "The correct sequence of cell cycle phases is:", options: ["G₁ → S → G₂ → M", "M → G₁ → S → G₂", "S → G₁ → G₂ → M", "G₁ → G₂ → S → M"], ans: 0, exp: "Cell cycle: Interphase (G₁ + S + G₂) + Mitotic phase (M). G₁: cell growth; S: DNA synthesis/replication; G₂: preparation for division; M: mitosis (PMAT). NCERT Class 11, Ch 10.", stars: 5 },
  { id: 18, subject: "Biology", section: "Botany", q: "During meiosis I, the homologous chromosomes separate. This stage is:", options: ["Metaphase I", "Anaphase I", "Telophase I", "Prophase I"], ans: 1, exp: "Meiosis I (reductional division): Prophase I (synapsis, crossing over) → Metaphase I (bivalents at equatorial plate) → Anaphase I (homologous chromosomes separate to poles) → Telophase I. Anaphase I reduces chromosome number from 2n to n. NCERT Class 11, Ch 10.", stars: 4 },
  { id: 19, subject: "Biology", section: "Botany", q: "Which feature of the nucleus was first described to contain DNA?", options: ["Nucleolus", "Nuclear pore", "Chromatin", "Nuclear envelope"], ans: 2, exp: "Chromatin = DNA + histone proteins (H1, H2A, H2B, H3, H4). 2 copies each of H2A, H2B, H3, H4 form histone octamer → nucleosome (146 bp DNA wrapped around). H1 binds linker DNA. NCERT Class 11, Ch 8.", stars: 4 },
  { id: 20, subject: "Biology", section: "Botany", q: "Pollination by wind is called:", options: ["Entomophily", "Anemophily", "Hydrophily", "Ornithophily"], ans: 1, exp: "Pollination types: Anemophily (wind) — light, non-sticky pollen, feathery stigma; Entomophily (insects) — colourful, fragrant, sticky pollen; Hydrophily (water) — e.g., Vallisneria, Hydrilla; Ornithophily (birds); Chiropterophily (bats). NCERT Class 12, Ch 2.", stars: 4 },
  { id: 21, subject: "Biology", section: "Botany", q: "In angiosperms, the endosperm nucleus is:", options: ["Diploid (2n)", "Haploid (n)", "Triploid (3n)", "Tetraploid (4n)"], ans: 2, exp: "Primary endosperm nucleus (PEN): formed by fusion of one male gamete (n) + 2 polar nuclei (n+n) = 3n (triploid). Endosperm provides nutrition to developing embryo. In coconut, liquid endosperm = coconut water; solid = coconut meat. NCERT Class 12, Ch 2.", stars: 5 },
  { id: 22, subject: "Biology", section: "Botany", q: "The microsporogenesis leads to formation of which cells?", options: ["Megaspores", "Microspores (pollen grains)", "Embryo sac", "Seeds"], ans: 1, exp: "Microsporogenesis: Microspore mother cell (MMC, 2n) → Meiosis → 4 microspores (n) → pollen grains. Occurs in anther loculi. Megasporogenesis: Megaspore mother cell (MMC) → Meiosis → 4 megaspores → only 1 functional megaspore → embryo sac. NCERT Class 12, Ch 2.", stars: 4 },
  { id: 23, subject: "Biology", section: "Botany", q: "Which plant group shows alternation of generations with dominant gametophyte?", options: ["Angiosperms", "Gymnosperms", "Bryophytes", "Pteridophytes"], ans: 2, exp: "Alternation of generations: Bryophytes — gametophyte (n) dominant, sporophyte (2n) dependent. Pteridophytes — sporophyte dominant, gametophyte independent (prothallus). Gymnosperms & Angiosperms — sporophyte dominant, gametophyte highly reduced. NCERT Class 11, Ch 3.", stars: 4 },
  { id: 24, subject: "Biology", section: "Botany", q: "Gymnosperms are called naked-seed plants because:", options: ["Both A and R are true, and R is the correct explanation of A", "Both A and R are true, but R is NOT the correct explanation", "A is true, R is false", "A is false, R is true"], ans: 0, exp: "Gymnosperms (gymnos=naked, sperma=seed): ovules are born on open megasporophylls (not enclosed in ovary). Hence NO fruit is formed. Examples: Cycas, Pinus, Ginkgo. NCERT Class 11, Ch 3.", stars: 4 },
  { id: 25, subject: "Biology", section: "Botany", q: "Which of the following is a false fruit (pseudocarp)?", options: ["Mango", "Tomato", "Apple", "Grape"], ans: 2, exp: "True fruit: developed from ovary wall (pericarp). False fruit (pseudocarp): develops from thalamus or other parts. Apple: edible fleshy part = swollen thalamus; actual fruit (core) = ovary. NCERT Class 12, Ch 2.", stars: 4 },
  { id: 26, subject: "Biology", section: "Botany", q: "Vascular bundles in monocot stems are:", options: ["Open and arranged in a ring", "Closed and scattered throughout the ground tissue", "Open and scattered", "Closed and arranged in a ring"], ans: 1, exp: "Monocot stem: vascular bundles are conjoint collateral CLOSED (no cambium) and scattered throughout ground tissue (atactostele). Dicot stem: open bundles (with cambium), arranged in a ring (eustele). NCERT Class 11, Ch 6.", stars: 4 },
  { id: 27, subject: "Biology", section: "Botany", q: "Pneumatophores are present in:", options: ["Mesophytes", "Mangrove plants (halophytes)", "Desert plants (xerophytes)", "Hydrophytes"], ans: 1, exp: "Pneumatophores = breathing roots (respiratory roots) of mangroves (e.g., Rhizophora, Avicennia). They grow vertically upward from soil (negative geotropism) to facilitate gaseous exchange in waterlogged, oxygen-poor soil. NCERT Class 11, Ch 5.", stars: 4 },
  { id: 28, subject: "Biology", section: "Botany", q: "The enzyme responsible for CO₂ fixation in the dark reaction of photosynthesis in C3 plants is:", options: ["PEP carboxylase", "RuBisCO", "ATP synthase", "NADP reductase"], ans: 1, exp: "RuBisCO is the most abundant protein on Earth. In C3 plants, RuBisCO fixes CO₂ onto RuBP in mesophyll cells. In C4 plants, INITIAL fixation is by PEP carboxylase in mesophyll; then RuBisCO in bundle sheath cells. NCERT Class 11, Ch 13.", stars: 5 },
  { id: 29, subject: "Biology", section: "Botany", q: "Pfr form of phytochrome promotes flowering in:", options: ["Short day plants (SDP)", "Long day plants (LDP)", "Day-neutral plants", "All flowering plants equally"], ans: 1, exp: "Phytochrome: Pr (660nm red light) ↔ Pfr (730nm far-red light, active form). Pfr promotes flowering in LDP (e.g., Wheat, Barley, Spinach). In SDP (e.g., Tobacco, Soybean), Pfr INHIBITS flowering. NCERT Class 11, Ch 15.", stars: 4 },
  { id: 30, subject: "Biology", section: "Botany", q: "Plasmolysis occurs when a cell is placed in:", options: ["Hypotonic solution", "Hypertonic solution", "Isotonic solution", "Distilled water"], ans: 1, exp: "Plasmolysis: In hypertonic solution, water moves out of cell by osmosis (exosmosis) → cell membrane shrinks away from cell wall → plasmolysis. Turgor pressure falls to zero → incipient plasmolysis. NCERT Class 11, Ch 11.", stars: 4 },
  { id: 31, subject: "Biology", section: "Botany", q: "The sigmoid (S-shaped) growth curve in plants follows the phase sequence:", options: ["Lag → Exponential → Stationary → Decline", "Exponential → Lag → Stationary", "Lag → Log → Decline", "Stationary → Log → Lag"], ans: 0, exp: "Plant growth curve: Lag phase (slow, cell division starts) → Exponential/Log phase (rapid cell division and elongation) → Stationary phase (maturation, growth rate slows) → Decline (senescence). NCERT Class 11, Ch 15.", stars: 4 },
  { id: 32, subject: "Biology", section: "Botany", q: "Casparian strips are present in:", options: ["Epidermis", "Endodermis of roots", "Cortex", "Pericycle"], ans: 1, exp: "Casparian strips: Suberin-impregnated bands on radial and transverse walls of endodermal cells. They prevent apoplastic movement of water and minerals into the stele — all water and solutes MUST pass through symplast (through cell membrane), enabling selective uptake. NCERT Class 11, Ch 11.", stars: 4 },
  { id: 33, subject: "Biology", section: "Botany", q: "Which of the following is the correct product of light reactions of photosynthesis?", options: ["Glucose, O₂, CO₂", "ATP, NADPH, O₂", "3-PGA, G3P", "CO₂, H₂O, ATP"], ans: 1, exp: "Light reactions (thylakoid membrane): Light energy → ATP (cyclic/non-cyclic photophosphorylation) + NADPH (by PS I & PS II) + O₂ (from water splitting/photolysis). These are used in dark reactions (Calvin cycle) to fix CO₂. NCERT Class 11, Ch 13.", stars: 5 },
  { id: 34, subject: "Biology", section: "Botany", q: "Which gas is produced in plants under anaerobic conditions?", options: ["CO₂ only", "Ethanol + CO₂", "Lactic acid only", "O₂"], ans: 1, exp: "Fermentation (anaerobic respiration) in plants/yeast: Pyruvate → Acetaldehyde (CO₂ released) → Ethanol. In mammals: Pyruvate → Lactate (lactic acid). Net ATP in fermentation = 2 (only glycolysis). NCERT Class 11, Ch 14.", stars: 4 },
  { id: 35, subject: "Biology", section: "Botany", q: "Senescence in plants is delayed by:", options: ["ABA", "Ethylene", "Cytokinin", "IAA"], ans: 2, exp: "Cytokinin (e.g., kinetin, zeatin): synthesized in roots, promotes cell division, delays senescence (Richmond-Lang effect — keeps leaves green by mobilizing nutrients). ABA and ethylene PROMOTE senescence. NCERT Class 11, Ch 15.", stars: 5 },
  { id: 36, subject: "Biology", section: "Botany", q: "Pollen grains have a tough outer wall called exine made of:", options: ["Cellulose", "Sporopollenin", "Lignin", "Pectin"], ans: 1, exp: "Exine = outer layer of pollen wall, composed of sporopollenin (most resistant biological material known — resistant to high temperatures, acids, alkalis, enzymes). Hence pollen grains are well preserved as fossils. Intine = inner layer of cellulose and pectin. NCERT Class 12, Ch 2.", stars: 4 },
  { id: 37, subject: "Biology", section: "Botany", q: "Which of the following represents a fibrous root system?", options: ["Carrot", "Radish", "Wheat", "Turnip"], ans: 2, exp: "Fibrous root system: characteristic of monocots. Adventitious roots from base of stem, similar in size. Examples: Wheat, Maize, Grass, Sugarcane. Tap root system: characteristic of dicots, primary root persists. Examples: Carrot, Radish, Turnip (modified tap roots). NCERT Class 11, Ch 5.", stars: 4 },
  { id: 38, subject: "Biology", section: "Botany", q: "The quantum yield is maximum for which colour of light in photosynthesis?", options: ["Green light", "Blue light", "Red light", "Yellow light"], ans: 2, exp: "Red light (680nm, PS II & PS I) gives maximum quantum yield in photosynthesis. Green light is least effective (most reflected — that's why plants appear green). Emerson's enhancement effect: Red + Far-red light together give more photosynthesis than either alone. NCERT Class 11, Ch 13.", stars: 4 },
  { id: 39, subject: "Biology", section: "Botany", q: "Seed germination requires all of the following EXCEPT:", options: ["Water", "Adequate temperature", "Light (always required)", "Oxygen"], ans: 2, exp: "Seed germination requirements: (1) Water (imbibition activates enzymes), (2) Optimal temperature, (3) O₂ (for aerobic respiration to provide energy). Light is NOT always required — many seeds are light-neutral. Some seeds need light (positively photoblastic: lettuce), others inhibited by light (negatively photoblastic: onion). NCERT Class 11, Ch 15.", stars: 4 },
  { id: 40, subject: "Biology", section: "Botany", q: "Parthenocarpy results in formation of:", options: ["Seedless fruits", "Seed without fruit", "Double seeds", "Multiple fruits"], ans: 0, exp: "Parthenocarpy: fruit development without fertilization → seedless fruits. Induced by: (1) Gibberellins spray (e.g., seedless grapes, tomato), (2) Auxin spray. Natural parthenocarpy: Banana, Seedless watermelon. NCERT Class 12, Ch 2.", stars: 4 },
  { id: 41, subject: "Biology", section: "Botany", q: "Guard cells regulate transpiration by controlling:", options: ["Root pressure", "Stomatal opening and closing", "Leaf area", "Cuticle thickness"], ans: 1, exp: "Guard cells: kidney-shaped (dicots) or dumbbell-shaped (monocots/grasses). Opening: K⁺ ions enter guard cells → water follows → guard cells swell → stomata open. Closing: K⁺ exit → water follows → stomata close. ABA triggers stomatal closure under drought stress. NCERT Class 11, Ch 11.", stars: 4 },
  { id: 42, subject: "Biology", section: "Botany", q: "Herbaceous plants with reticulate venation belong to:", options: ["Monocotyledons", "Dicotyledons", "Gymnosperms", "Pteridophytes"], ans: 1, exp: "Dicot characters: reticulate (net) venation, tap root, two cotyledons, tetramerous/pentamerous flowers, open vascular bundles. Monocot characters: parallel venation, fibrous roots, one cotyledon, trimerous flowers, closed vascular bundles. NCERT Class 11, Ch 5.", stars: 4 },
  { id: 43, subject: "Biology", section: "Botany", q: "The process of vernalization involves:", options: ["Treatment with red light", "Exposure to low temperature to accelerate flowering", "Application of gibberellin", "Removal of leaves before flowering"], ans: 1, exp: "Vernalization: exposure to cold temperature (0-10°C for several weeks) to fulfil requirement for flowering (acceleration of flowering). Examples: Winter wheat, Rye, Beet. Eliminates/reduces vegetative phase. Site of perception: shoot apex. NCERT Class 11, Ch 15.", stars: 4 },
  { id: 44, subject: "Biology", section: "Botany", q: "In the process of photorespiration, the glycolate formed in the chloroplast is oxidized in:", options: ["Mitochondria", "Peroxisome", "Glyoxisome", "Vacuole"], ans: 1, exp: "Photorespiration pathway: Chloroplast (RuBP + O₂ → phosphoglycolate → glycolate) → Peroxisome (glycolate oxidized → glyoxylate → glycine) → Mitochondria (2 glycine → serine + CO₂ + NH₃) → Peroxisome → Chloroplast. NCERT Class 11, Ch 13.", stars: 4 },
  { id: 45, subject: "Biology", section: "Botany", q: "Protoplast fusion for somatic hybridization involves removal of cell wall using:", options: ["Cellulase and pectinase", "Amylase and lipase", "Protease and nuclease", "Lysozyme"], ans: 0, exp: "Somatic hybridization (parasexual hybridization): (1) Remove cell wall using cellulase + pectinase → protoplasts; (2) Fuse protoplasts using PEG (polyethylene glycol) or electrofusion; (3) Culture → somatic hybrid. Example: Pomato (Potato + Tomato). NCERT Class 12, Ch 9.", stars: 4 },
  // BIOLOGY - ZOOLOGY (46-90)
  { id: 46, subject: "Biology", section: "Zoology", q: "The proton gradient across the inner mitochondrial membrane drives ATP synthesis by:", options: ["Substrate-level phosphorylation", "Oxidative phosphorylation via ATP synthase (chemiosmosis)", "Fermentation", "GTP hydrolysis"], ans: 1, exp: "Mitchell's chemiosmotic hypothesis: NADH/FADH₂ → electron transport chain → proton (H⁺) pumped from matrix to intermembrane space → proton gradient (electrochemical) → H⁺ flows back through ATP synthase (F₀F₁) → ATP synthesis. NCERT Class 11, Ch 14.", stars: 5 },
  { id: 47, subject: "Biology", section: "Zoology", q: "Which of the following is the correct sequence of organelles in protein synthesis and secretion?", options: ["Ribosome → Golgi → ER → Cell membrane", "Ribosome → ER → Golgi → Cell membrane", "ER → Ribosome → Golgi → Cell membrane", "Golgi → Ribosome → ER → Cell membrane"], ans: 1, exp: "Protein secretion pathway: Ribosomes (on RER, translation) → Rough ER (folding, glycosylation) → Transport vesicles → Golgi apparatus (processing, packaging) → Secretory vesicles → Cell membrane (exocytosis). NCERT Class 11, Ch 8.", stars: 5 },
  { id: 48, subject: "Biology", section: "Zoology", q: "In Hardy-Weinberg equilibrium, the allele frequencies in a population remain constant when:", options: ["Natural selection occurs", "Random mating, no selection, no mutation, no genetic drift, no migration", "Population size is small", "Genetic drift is occurring"], ans: 1, exp: "Hardy-Weinberg principle: p + q = 1; p² + 2pq + q² = 1. Equilibrium requires: (1) Large population, (2) Random mating, (3) No natural selection, (4) No mutation, (5) No gene flow (migration). NCERT Class 12, Ch 7.", stars: 5 },
  { id: 49, subject: "Biology", section: "Zoology", q: "The function of lymph nodes in the lymphatic system is:", options: ["Produce red blood cells", "Filter lymph and house lymphocytes for immune response", "Produce plasma proteins", "Store fat"], ans: 1, exp: "Lymph nodes: Bean-shaped structures along lymphatic vessels. Function: (1) Filter pathogens/foreign particles from lymph, (2) House B and T lymphocytes, (3) Mount immune response against antigens. Lymph is tissue fluid that enters lymphatic capillaries. NCERT Class 11, Ch 18.", stars: 4 },
  { id: 50, subject: "Biology", section: "Zoology", q: "In which phase of the cell cycle does DNA replication occur?", options: ["G₁ phase", "S phase", "G₂ phase", "M phase"], ans: 1, exp: "S phase (Synthesis phase): DNA replication occurs. Each chromosome duplicates → 2 chromatids joined by centromere. After S phase, cell has twice the DNA content (4N) but same chromosome number (2N). G₁: growth; G₂: preparation for division. NCERT Class 11, Ch 10.", stars: 5 },
  { id: 51, subject: "Biology", section: "Zoology", q: "Sickle cell anaemia is caused by a mutation in:", options: ["α-globin gene", "β-globin gene (Glu → Val at position 6)", "Haemoglobin A → B", "Myoglobin gene"], ans: 1, exp: "Sickle cell anaemia: autosomal recessive. Point mutation: β-globin gene codon 6 — GAG → GTG → Glutamic acid (hydrophilic) → Valine (hydrophobic). HbS polymerises under low O₂ → sickle-shaped RBCs → haemolysis → anaemia. NCERT Class 12, Ch 5.", stars: 5 },
  { id: 52, subject: "Biology", section: "Zoology", q: "The site of fertilization in the human female reproductive tract is:", options: ["Uterus", "Fallopian tube (ampulla)", "Ovary", "Cervix"], ans: 1, exp: "Fertilization normally occurs in the ampullary-isthmic junction (ampulla) of the fallopian tube (oviduct). The egg is viable for ~12-24 hours post-ovulation. Sperm capacitation occurs in the female reproductive tract. NCERT Class 12, Ch 3.", stars: 5 },
  { id: 53, subject: "Biology", section: "Zoology", q: "Which of the following is a correct example of innate immunity?", options: ["Antibody production", "Natural killer cells and phagocytes", "Memory B cells", "T-cell activation"], ans: 1, exp: "Innate immunity (non-specific): (1) Physical barriers (skin, mucus), (2) Phagocytes (neutrophils, macrophages), (3) Natural killer (NK) cells, (4) Complement system, (5) Interferons. Adaptive (specific) immunity: B cells, T cells, antibodies, memory cells. NCERT Class 12, Ch 8.", stars: 4 },
  { id: 54, subject: "Biology", section: "Zoology", q: "Insulin is produced by which cells of the pancreas?", options: ["Alpha cells", "Beta cells of islets of Langerhans", "Delta cells", "Acinar cells"], ans: 1, exp: "Pancreatic islets of Langerhans: α cells → Glucagon (raises blood glucose), β cells → Insulin (lowers blood glucose by promoting glucose uptake into cells), δ cells → Somatostatin. Diabetes mellitus: Type 1 (autoimmune destruction of β cells), Type 2 (insulin resistance). NCERT Class 11, Ch 22.", stars: 5 },
  { id: 55, subject: "Biology", section: "Zoology", q: "Glomerular filtration rate (GFR) in a healthy adult is approximately:", options: ["1 L/day", "125 mL/min (180 L/day)", "1 mL/min", "10 L/day"], ans: 1, exp: "GFR = 125 mL/min = 180 L/day. Of this, 99% is reabsorbed; only ~1-1.5 L is excreted as urine. Ultrafiltration through glomerular capillaries (fenestrated endothelium + basement membrane + podocytes) separates plasma from blood cells and large proteins. NCERT Class 11, Ch 19.", stars: 5 },
  { id: 56, subject: "Biology", section: "Zoology", q: "The primary sex ratio in humans (at fertilization) is:", options: ["1:1 (XX:XY)", "Approximately 1:1.05 (female:male)", "2:1 (female:male)", "1:2 (female:male)"], ans: 1, exp: "Primary sex ratio (at conception): ~105-106 males per 100 females. Secondary sex ratio (at birth): ~105 males per 100 females. Sex determination: XX = female; XY = male. Y chromosome carries SRY gene (sex-determining region Y) → testes development. NCERT Class 12, Ch 5.", stars: 4 },
  { id: 57, subject: "Biology", section: "Zoology", q: "Which of the following correctly describes the function of HCG (human chorionic gonadotropin)?", options: ["Promotes ovulation", "Maintains corpus luteum during early pregnancy", "Stimulates milk production", "Promotes implantation"], ans: 1, exp: "HCG (secreted by trophoblast/placenta): maintains corpus luteum → continued progesterone secretion → maintains endometrium → prevents menstruation. HCG detected in urine by day 9 post-fertilization (basis of pregnancy tests). Declines after 1st trimester as placenta takes over progesterone production. NCERT Class 12, Ch 3.", stars: 5 },
  { id: 58, subject: "Biology", section: "Zoology", q: "Which type of WBC is the most abundant in human blood?", options: ["Eosinophils", "Basophils", "Neutrophils", "Monocytes"], ans: 2, exp: "WBC differential count (normal): Neutrophils 60-70% (most abundant), Lymphocytes 20-25%, Monocytes 2-8%, Eosinophils 1-4%, Basophils 0.5-1%. Neutrophils: first responders to bacterial infection (phagocytosis). NCERT Class 11, Ch 18.", stars: 4 },
  { id: 59, subject: "Biology", section: "Zoology", q: "Biogas production involves which type of microorganisms as primary producers of methane?", options: ["Aerobic bacteria", "Methanogenic archaea (anaerobic)", "Nitrifying bacteria", "Sulphur bacteria"], ans: 1, exp: "Biogas: produced by anaerobic digestion of organic matter. Methanogenic archaea (methanogens): Methanobacterium, Methanococcus convert organic acids → CH₄ + CO₂. Biogas: ~60% CH₄, ~40% CO₂. Used as fuel in rural areas. NCERT Class 12, Ch 10.", stars: 4 },
  { id: 60, subject: "Biology", section: "Zoology", q: "The resting membrane potential of a neuron is approximately:", options: ["+70 mV", "−70 mV (inside negative relative to outside)", "0 mV", "+35 mV"], ans: 1, exp: "Resting membrane potential: −70 mV (inside negative). Maintained by: (1) Na⁺-K⁺ ATPase pump (3 Na⁺ out, 2 K⁺ in), (2) High K⁺ permeability at rest. Action potential: depolarization (Na⁺ rush in → +35 mV) → repolarization (K⁺ rush out). NCERT Class 11, Ch 21.", stars: 5 },
  { id: 61, subject: "Biology", section: "Zoology", q: "The 'all-or-none' law applies to:", options: ["Muscle fibre contraction", "Heart beat", "Nerve impulse conduction", "All of the above"], ans: 2, exp: "All-or-none law: A nerve impulse is either generated fully or not at all — there is no partial response. The threshold stimulus must be reached. If reached, the full action potential fires regardless of stimulus intensity. Applies to single nerve fibres. NCERT Class 11, Ch 21.", stars: 4 },
  { id: 62, subject: "Biology", section: "Zoology", q: "The process of humoral immunity involves:", options: ["T-killer cells directly attacking pathogens", "B cells producing antibodies against antigens", "NK cells destroying infected cells", "Phagocytosis by macrophages only"], ans: 1, exp: "Humoral immunity: B lymphocytes → activated by antigen → plasma cells → secrete antibodies (immunoglobulins: IgG, IgM, IgA, IgE, IgD). Memory B cells provide secondary immune response. Cell-mediated immunity: T lymphocytes (CTL, helper T cells, regulatory T cells). NCERT Class 12, Ch 8.", stars: 5 },
  { id: 63, subject: "Biology", section: "Zoology", q: "Which disease is caused by Trypanosoma and transmitted by the tsetse fly?", options: ["Kala-azar", "Sleeping sickness (African trypanosomiasis)", "Malaria", "Filariasis"], ans: 1, exp: "Sleeping sickness (African trypanosomiasis): caused by Trypanosoma brucei, transmitted by tsetse fly (Glossina). Kala-azar: Leishmania donovani, sandfly vector. Malaria: Plasmodium spp., Anopheles mosquito. Filariasis: Wuchereria bancrofti, Culex mosquito. NCERT Class 12, Ch 8.", stars: 4 },
  { id: 64, subject: "Biology", section: "Zoology", q: "The Golgi apparatus is involved in all of the following EXCEPT:", options: ["Sorting and packaging of proteins", "Formation of lysosomes", "Synthesis of proteins", "Addition of sugar residues to glycoproteins"], ans: 2, exp: "Golgi apparatus (Camillo Golgi): (1) Sorting, packaging, modifying proteins from ER, (2) Forming glycoproteins (adding sugar residues), (3) Forming lysosomes (from trans face), (4) Secretion. Golgi does NOT synthesize proteins — this occurs on ribosomes. NCERT Class 11, Ch 8.", stars: 4 },
  { id: 65, subject: "Biology", section: "Zoology", q: "Crossing over during meiosis occurs in:", options: ["Leptotene", "Zygotene", "Pachytene", "Diplotene"], ans: 2, exp: "Prophase I sub-stages: L-Z-P-D-Di (Leptotene-Zygotene-Pachytene-Diplotene-Diakinesis). Pachytene: crossing over (exchange of segments between non-sister chromatids of homologous chromosomes) by enzyme recombinase at chiasmata. Zygotene: synapsis occurs. NCERT Class 11, Ch 10.", stars: 5 },
  { id: 66, subject: "Biology", section: "Zoology", q: "What is the role of erythropoietin (EPO)?", options: ["Regulate blood pressure", "Stimulate red blood cell production in bone marrow", "Regulate blood glucose", "Stimulate white blood cell production"], ans: 1, exp: "Erythropoietin (EPO): glycoprotein hormone secreted by peritubular cells of kidney (and liver). Stimulates erythropoiesis (RBC production) in red bone marrow. Produced in response to hypoxia (low O₂). NCERT Class 11, Ch 22 and Ch 18.", stars: 4 },
  { id: 67, subject: "Biology", section: "Zoology", q: "The knee-jerk reflex (patellar reflex) is an example of:", options: ["Conditioned reflex", "Monosynaptic spinal reflex", "Polysynaptic reflex", "Cranial reflex"], ans: 1, exp: "Patellar (knee-jerk) reflex: monosynaptic spinal reflex arc. Tendon tap → muscle spindle stretch → Ia afferent fibre → directly synapses on motor neuron in spinal cord → quadriceps contraction. No interneuron (monosynaptic). NCERT Class 11, Ch 21.", stars: 4 },
  { id: 68, subject: "Biology", section: "Zoology", q: "The acrosome reaction in fertilization is triggered by:", options: ["Zona pellucida contact (ZP3 glycoprotein)", "Corona radiata", "Progesterone only", "Calcium ions only"], ans: 0, exp: "Acrosome reaction: Sperm contacts zona pellucida → ZP3 receptor on sperm head activated → Ca²⁺ influx → acrosomal vesicle fuses with sperm plasma membrane → acrosin (enzyme) released → zona pellucida penetration. NCERT Class 12, Ch 3.", stars: 4 },
  { id: 69, subject: "Biology", section: "Zoology", q: "Which of the following is involved in blood clotting (coagulation cascade)?", options: ["Fibrinogen → Fibrin (by thrombin)", "Haemoglobin → clot", "Albumin → fibrin", "Globulin → prothrombin"], ans: 0, exp: "Blood clotting: Platelet aggregation → Coagulation cascade → Prothrombin → Thrombin (by prothrombinase) → Fibrinogen → Fibrin (mesh). Vitamin K is required for synthesis of clotting factors II, VII, IX, X. NCERT Class 11, Ch 18.", stars: 4 },
  { id: 70, subject: "Biology", section: "Zoology", q: "Which part of the human brain controls voluntary movement, reasoning, and speech?", options: ["Cerebellum", "Hypothalamus", "Cerebrum (cerebral cortex)", "Medulla oblongata"], ans: 2, exp: "Cerebrum (cerebral cortex, forebrain): reasoning, memory, learning, voluntary movement (motor cortex), sensory perception (sensory cortex), speech (Broca's area), language comprehension (Wernicke's area). Largest part of human brain. NCERT Class 11, Ch 21.", stars: 5 },
  { id: 71, subject: "Biology", section: "Zoology", q: "The type of RNA that brings amino acids to the ribosome during translation is:", options: ["mRNA", "rRNA", "tRNA", "snRNA"], ans: 2, exp: "tRNA (transfer RNA): clover-leaf 3D structure. Has anticodon loop (3 nucleotides complementary to mRNA codon) + amino acid attachment site (3'-CCA-OH). Specific aminoacyl-tRNA synthetases charge each tRNA with correct amino acid. NCERT Class 12, Ch 6.", stars: 5 },
  { id: 72, subject: "Biology", section: "Zoology", q: "Turner syndrome (45, XO) is characterized by:", options: ["Tall stature, male phenotype", "Short stature, female phenotype, sterile, underdeveloped ovaries", "Extra Y chromosome", "Normal female with trisomy"], ans: 1, exp: "Turner syndrome (45, X or 45, XO): Monosomy X. Features: short stature, webbed neck, shield chest, underdeveloped ovaries (streak gonads) → primary amenorrhoea, sterile. IQ normal. Treated with oestrogen. NCERT Class 12, Ch 5.", stars: 5 },
  { id: 73, subject: "Biology", section: "Zoology", q: "Biofortification refers to:", options: ["Adding nutrients to processed food", "Developing crops with higher nutritional value through breeding/GM", "Preservation of food by irradiation", "Fermentation of food to increase vitamins"], ans: 1, exp: "Biofortification: developing crops with improved nutritional content through plant breeding or genetic modification. Examples: Golden Rice (β-carotene/Vitamin A), Maize hybrids (methionine-rich), Wheat (Atlas 66, high protein). NCERT Class 12, Ch 9.", stars: 4 },
  { id: 74, subject: "Biology", section: "Zoology", q: "The process of transcription in eukaryotes occurs in:", options: ["Cytoplasm", "Nucleus (RNA then moves to cytoplasm)", "Ribosome", "Mitochondria only"], ans: 1, exp: "Eukaryotic transcription: occurs in nucleus by RNA polymerase II (mRNA), I (rRNA), III (tRNA, snRNA). Pre-mRNA undergoes processing: 5' capping, poly-A tailing, splicing (introns removed, exons joined) → mature mRNA → moves to cytoplasm for translation. NCERT Class 12, Ch 6.", stars: 5 },
  { id: 75, subject: "Biology", section: "Zoology", q: "Which of the following is an example of a frameshift mutation?", options: ["Substitution of one base", "Insertion or deletion of a base (not in multiples of 3)", "Inversion of a chromosome segment", "Translocation"], ans: 1, exp: "Frameshift mutation: insertion or deletion of nucleotides (not multiples of 3) → shifts reading frame → all downstream codons altered → usually nonfunctional protein. Point mutation (substitution) may be silent, missense, or nonsense. NCERT Class 12, Ch 6.", stars: 4 },
  { id: 76, subject: "Biology", section: "Zoology", q: "The role of colostrum in newborn immunity is:", options: ["Provides energy only", "Contains IgA antibodies providing passive immunity", "Contains IgG only", "Provides active immunity"], ans: 1, exp: "Colostrum (first milk): yellowish fluid secreted in first few days after birth. Rich in IgA antibodies → passive immunity to newborn against gut pathogens. Also contains lactoferrin, lysozyme, immune cells, growth factors. NCERT Class 12, Ch 8.", stars: 4 },
  { id: 77, subject: "Biology", section: "Zoology", q: "Biodegradable waste is best disposed of by:", options: ["Incineration", "Composting and vermicomposting", "Land filling", "Recycling only"], ans: 1, exp: "Biodegradable waste: decomposed by microorganisms. Best disposal: composting (aerobic decomposition → humus), vermicomposting (earthworms). Non-biodegradable: plastics, metals → recycling or safe disposal. NCERT Class 12, Ch 16.", stars: 3 },
  { id: 78, subject: "Biology", section: "Zoology", q: "The Montreal Protocol (1987) was signed to protect:", options: ["Tropical forests", "Stratospheric ozone layer (reduce CFCs)", "Marine biodiversity", "River systems"], ans: 1, exp: "Montreal Protocol (1987): international treaty to phase out substances depleting stratospheric ozone (mainly CFCs — chlorofluorocarbons). Ozone (O₃) layer absorbs harmful UV-B radiation. Ozone hole: mainly over Antarctica (polar stratospheric clouds). NCERT Class 12, Ch 16.", stars: 4 },
  { id: 79, subject: "Biology", section: "Zoology", q: "Human Genome Project revealed that the human genome has approximately how many protein-coding genes?", options: ["3.2 billion", "80,000–1,00,000", "20,000–25,000", "2,000"], ans: 2, exp: "HGP findings: ~3.2 billion base pairs; ~20,000–25,000 protein-coding genes (only ~1.5% of genome is coding); ~99.9% of sequence identical between any two individuals. NCERT Class 12, Ch 6.", stars: 5 },
  { id: 80, subject: "Biology", section: "Zoology", q: "Which of the following correctly pairs a pathogen with its disease?", options: ["Salmonella typhi — Cholera", "Vibrio cholerae — Cholera", "Plasmodium vivax — Kala-azar", "Wuchereria bancrofti — Malaria"], ans: 1, exp: "Pathogen-Disease pairs: Salmonella typhi → Typhoid; Vibrio cholerae → Cholera (rice-water stools); Plasmodium vivax/falciparum → Malaria; Wuchereria bancrofti → Filariasis (elephantiasis); Leishmania donovani → Kala-azar. NCERT Class 12, Ch 8.", stars: 5 },
  { id: 81, subject: "Biology", section: "Zoology", q: "In oogenesis, the secondary oocyte completes meiosis II only when:", options: ["Ovulation occurs", "Fertilization occurs (sperm entry)", "LH surge happens", "HCG is secreted"], ans: 1, exp: "Oogenesis: Primary oocyte arrested at Prophase I (birth to puberty). At puberty: LH surge → Meiosis I completes → Secondary oocyte + 1st polar body. Secondary oocyte arrested at Metaphase II. Fertilization (sperm entry) → Meiosis II completes → Ovum + 2nd polar body. NCERT Class 12, Ch 3.", stars: 5 },
  { id: 82, subject: "Biology", section: "Zoology", q: "The term 'ecotone' refers to:", options: ["A type of ecosystem", "Junction zone between two different ecosystems", "Endemic species zone", "Climate zone"], ans: 1, exp: "Ecotone: transition zone between two different ecosystems (e.g., forest-grassland boundary, mangrove between land and sea). Shows edge effect — higher species diversity (both adjacent ecosystems' species present). NCERT Class 12, Ch 13.", stars: 4 },
  { id: 83, subject: "Biology", section: "Zoology", q: "The Km (Michaelis constant) of an enzyme represents:", options: ["Maximum velocity of reaction", "Substrate concentration at half-maximal velocity (affinity measure)", "Product concentration", "Enzyme concentration"], ans: 1, exp: "Michaelis-Menten kinetics: Km = substrate concentration ([S]) at which reaction velocity = Vmax/2. Low Km → high affinity (less substrate needed). High Km → low affinity (more substrate needed). Competitive inhibitor increases apparent Km; non-competitive does not. NCERT Class 11, Ch 9.", stars: 5 },
  { id: 84, subject: "Biology", section: "Zoology", q: "Adaptive radiation is best exemplified by:", options: ["Darwin's finches on Galapagos Islands", "Industrial melanism in peppered moth", "Giraffe's long neck", "Peacock's plumage"], ans: 0, exp: "Adaptive radiation: evolution of multiple species from a common ancestor in response to different ecological niches. Darwin's finches (Galapagos): 14 species evolved from one common ancestor, each with beak adapted to different food sources. Also: Australian marsupials, Hawaiian honeycreepers. NCERT Class 12, Ch 7.", stars: 5 },
  { id: 85, subject: "Biology", section: "Zoology", q: "Which of the following correctly describes the role of restriction enzymes in recombinant DNA technology?", options: ["Join DNA fragments", "Cut DNA at specific palindromic sequences", "Amplify DNA", "Remove RNA from DNA"], ans: 1, exp: "Restriction endonucleases (molecular scissors): Type II enzymes cut DNA at specific palindromic sequences producing sticky ends (e.g., EcoRI: G↓AATTC) or blunt ends (e.g., SmaI: CCC↓GGG). First isolated from bacteria as defence against bacteriophages. NCERT Class 12, Ch 11.", stars: 5 },
  { id: 86, subject: "Biology", section: "Zoology", q: "Which is the correct site of haematopoiesis (blood cell formation) in adults?", options: ["Liver", "Spleen", "Red bone marrow", "Lymph nodes"], ans: 2, exp: "Haematopoiesis in adults: Red bone marrow (flat bones: sternum, ribs, vertebrae, pelvis). Produces: RBCs, WBCs (except mature T cells), platelets. In foetus: yolk sac → liver/spleen → bone marrow. NCERT Class 11, Ch 18.", stars: 4 },
  { id: 87, subject: "Biology", section: "Zoology", q: "Which of the following organisms shows complete metamorphosis (holometabolism)?", options: ["Grasshopper", "Cockroach", "Housefly (Musca domestica)", "Bug"], ans: 2, exp: "Complete metamorphosis (Holometabola): Egg → Larva → Pupa → Adult. Examples: Flies, Butterflies, Beetles, Bees. Incomplete metamorphosis (Hemimetabola): Egg → Nymph → Adult (no pupal stage). Examples: Cockroach, Grasshopper, Bug. NCERT Class 11, Ch 16.", stars: 4 },
  { id: 88, subject: "Biology", section: "Zoology", q: "Ozone is destroyed in the stratosphere primarily by:", options: ["CO₂", "Chlorine radicals from CFCs (Cl + O₃ → ClO + O₂)", "Methane", "Sulphur dioxide"], ans: 1, exp: "Ozone depletion mechanism: CFCs (freons) released from refrigerants, AC units → reach stratosphere → UV radiation releases Cl radicals → Cl + O₃ → ClO + O₂ → ClO + O → Cl + O₂ (chain reaction). One Cl atom destroys ~1 lakh O₃ molecules. NCERT Class 12, Ch 16.", stars: 4 },
  { id: 89, subject: "Biology", section: "Zoology", q: "The term 'golden rice' refers to:", options: ["Yellow coloured rice variety", "GM rice with β-carotene (provitamin A) biosynthesis genes from daffodil and bacteria", "Hybrid rice with high yield", "Rice with high carbohydrate content"], ans: 1, exp: "Golden Rice: GM variety developed by Ingo Potrykus & Peter Beyer. Contains genes from daffodil (Narcissus pseudonarcissus) and Erwinia uredovora → β-carotene (provitamin A) synthesis in endosperm. Aimed at preventing Vitamin A deficiency (leading cause of blindness in developing countries). NCERT Class 12, Ch 12.", stars: 5 },
  { id: 90, subject: "Biology", section: "Zoology", q: "Which of the following is NOT a biodiversity hotspot in India?", options: ["Eastern Himalayas", "Indo-Burma", "Western Ghats", "Deccan Plateau"], ans: 3, exp: "India's biodiversity hotspots: (1) Eastern Himalayas (extended Himalayan hotspot), (2) Indo-Burma (extends to NE India), (3) Sundaland (Nicobar Islands), (4) Western Ghats + Sri Lanka. Deccan Plateau is NOT a recognized hotspot. India has ~8.1% of world's biodiversity; 2.4% land area. NCERT Class 12, Ch 15.", stars: 4 },
  // CHEMISTRY (91-135)
  { id: 91, subject: "Chemistry", section: "Physical", q: "The rate of a zero-order reaction:", options: ["Is proportional to concentration", "Is independent of reactant concentration", "Doubles when concentration doubles", "Depends on temperature only"], ans: 1, exp: "Zero-order reaction: Rate = k[A]⁰ = k (constant, independent of concentration). Units of k: mol/L/s. Example: decomposition of NH₃ on platinum surface. Half-life: t₁/₂ = [A]₀/2k (decreases as reaction proceeds). NCERT Class 12, Ch 4.", stars: 4 },
  { id: 92, subject: "Chemistry", section: "Physical", q: "Van't Hoff factor 'i' for NaCl fully dissociated in dilute solution is:", options: ["1", "2", "3", "0.5"], ans: 1, exp: "Van't Hoff factor i = (observed colligative property)/(calculated for non-electrolyte). NaCl → Na⁺ + Cl⁻: i = 2. CaCl₂ → Ca²⁺ + 2Cl⁻: i = 3. Glucose (non-electrolyte): i = 1. Acetic acid (partial dissociation in water): i < 1 to 2. NCERT Class 12, Ch 2.", stars: 5 },
  { id: 93, subject: "Chemistry", section: "Physical", q: "Osmotic pressure (π) of a solution is given by:", options: ["π = MRT (van't Hoff equation)", "π = nRT/V", "π = CRT", "All of the above"], ans: 3, exp: "Osmotic pressure: π = MRT = CRT = nRT/V. M = molarity, R = 0.0821 L·atm/K·mol, T = temperature in Kelvin, C = concentration. Used to measure molecular mass of polymers (dilute solutions). Isotonic solutions have equal osmotic pressure. NCERT Class 12, Ch 2.", stars: 5 },
  { id: 94, subject: "Chemistry", section: "Physical", q: "The relationship between standard Gibbs free energy and EMF of a cell is:", options: ["ΔG° = nFE°cell", "ΔG° = −nFE°cell", "ΔG° = nRT ln K", "ΔG° = −RT ln Keq"], ans: 1, exp: "ΔG° = −nFE°cell. n = moles of electrons transferred, F = Faraday's constant (96485 C/mol). If E°cell > 0 → ΔG° < 0 → spontaneous. Nernst equation: E = E° − (RT/nF)ln Q = E° − (0.0592/n)log Q at 25°C. NCERT Class 12, Ch 3.", stars: 5 },
  { id: 95, subject: "Chemistry", section: "Physical", q: "Which of the following is a lyophilic colloid?", options: ["Gold sol", "Arsenic sulphide sol", "Starch in water", "Iron hydroxide sol"], ans: 2, exp: "Lyophilic (solvent-loving) colloids: dispersed phase has strong affinity for dispersion medium. Examples: starch, gelatin, gum, proteins in water. Stable, can be redispersed after coagulation. Lyophobic: gold sol, AgI sol, Fe(OH)₃ sol — opposite. NCERT Class 12, Ch 5.", stars: 4 },
  { id: 96, subject: "Chemistry", section: "Organic", q: "The IUPAC name of CH₃CH₂CHO is:", options: ["Propan-1-ol", "Propan-1-al", "Propanal", "2-methylethanal"], ans: 2, exp: "CH₃CH₂CHO: 3 carbons, aldehyde (-CHO) functional group. IUPAC name: propanal (propan-1-al is also acceptable). Aldehydes: -al suffix. Ketones: -one suffix. NCERT Class 12, Ch 12.", stars: 4 },
  { id: 97, subject: "Chemistry", section: "Organic", q: "Which of the following undergoes Cannizzaro reaction?", options: ["Acetaldehyde (CH₃CHO)", "Formaldehyde (HCHO, no α-H)", "Acetone", "Propionaldehyde"], ans: 1, exp: "Cannizzaro reaction: aldehydes WITHOUT α-H undergo self-oxidation/reduction (disproportionation) with conc. NaOH. HCHO → CH₃OH + HCOONa. Other examples: benzaldehyde, trimethylacetaldehyde. Aldehydes WITH α-H undergo aldol condensation instead. NCERT Class 12, Ch 12.", stars: 5 },
  { id: 98, subject: "Chemistry", section: "Organic", q: "The hydrolysis of methyl cyanide (CH₃CN) with dilute H₂SO₄ gives:", options: ["Methylamine", "Acetic acid (CH₃COOH)", "Methanol", "Formaldehyde"], ans: 1, exp: "Hydrolysis of nitriles: RCN + 2H₂O → RCOOH + NH₃ (in acidic or alkaline conditions). CH₃CN + 2H₂O (H⁺/OH⁻) → CH₃COOH + NH₃. This is a method to prepare carboxylic acids from nitriles. NCERT Class 12, Ch 12.", stars: 4 },
  { id: 99, subject: "Chemistry", section: "Organic", q: "The reagent used for the distinction of primary, secondary, and tertiary amines is:", options: ["HCl", "Hinsberg's reagent (benzenesulphonyl chloride)", "NaOH", "AgNO₃"], ans: 1, exp: "Hinsberg's test: benzenesulphonyl chloride (C₆H₅SO₂Cl). Primary amine → sulphonamide soluble in NaOH (acidic H present). Secondary amine → sulphonamide insoluble in NaOH (no acidic H). Tertiary amine → no reaction (no N-H). NCERT Class 12, Ch 13.", stars: 5 },
  { id: 100, subject: "Chemistry", section: "Organic", q: "Grignard reagent (RMgX) reacts with CO₂ followed by hydrolysis to give:", options: ["Alcohol", "Aldehyde", "Carboxylic acid (RCOOH)", "Ketone"], ans: 2, exp: "Grignard reagent + CO₂ → (after hydrolysis) carboxylic acid RCOOH (one more carbon than R group). Grignard + HCHO → 1° alcohol; Grignard + RCHO → 2° alcohol; Grignard + R₂C=O → 3° alcohol; Grignard + ester → 3° alcohol. NCERT Class 12, Ch 11.", stars: 5 },
  { id: 101, subject: "Chemistry", section: "Organic", q: "Which of the following reactions is used to prepare alkyl halides from alcohols?", options: ["Lucas test", "Halogenation using HX or SOCl₂ (acid halides)", "Wurtz reaction", "Swarts reaction"], ans: 1, exp: "Preparation of alkyl halides from alcohols: (1) ROH + HCl/ZnCl₂ (Lucas reagent) → RCl (for 3° most reactive), (2) ROH + SOCl₂ → RCl + SO₂ + HCl (best method), (3) ROH + PCl₃ → RCl. NCERT Class 12, Ch 10.", stars: 4 },
  { id: 102, subject: "Chemistry", section: "Inorganic", q: "The correct IUPAC name of [Co(NH₃)₆]Cl₃ is:", options: ["Hexaaminecobalt(III) chloride", "Hexaamminecobalt(III) chloride", "Triaminecobalt chloride", "Cobalt(III) hexaamine chloride"], ans: 1, exp: "IUPAC naming of coordination compounds: hexaammine (NH₃ × 6) cobalt(III) chloride. Rules: (1) Cation first, anion last, (2) Ligands in alphabetical order (with prefix), (3) Metal oxidation state in Roman numerals. Co: x + 0×6 = +3. NCERT Class 12, Ch 9.", stars: 5 },
  { id: 103, subject: "Chemistry", section: "Inorganic", q: "Which of the following d-block elements is NOT a transition element by the strict definition?", options: ["Iron (Fe)", "Copper (Cu)", "Zinc (Zn)", "Titanium (Ti)"], ans: 2, exp: "Transition elements: d-block elements with incompletely filled d-orbitals in ground state OR common oxidation states. Zinc (Zn): [Ar]3d¹⁰4s² — d¹⁰ (completely filled) in all stable forms (Zn²⁺: d¹⁰ too) → NOT a true transition element. Copper (Cu): d¹⁰s¹ in ground state BUT Cu⁺ (d¹⁰) and Cu²⁺ (d⁹). NCERT Class 12, Ch 8.", stars: 5 },
  { id: 104, subject: "Chemistry", section: "Inorganic", q: "The p-Block element that shows only +4 oxidation state (not +2) is:", options: ["Carbon (C)", "Silicon (Si)", "Tin (Sn)", "Lead (Pb)"], ans: 1, exp: "Group 14 oxidation states: C and Si show only +4 (no inert pair effect at light elements). Sn: +2 and +4 (Sn²⁺ less stable). Pb: prefers +2 due to strong inert pair effect (6s² inert). NCERT Class 12, Ch 7.", stars: 4 },
  { id: 105, subject: "Chemistry", section: "Inorganic", q: "Aqua regia dissolves gold because:", options: ["Strong oxidizing power of HNO₃ + complexing power of HCl (Cl⁻)", "Only HNO₃ oxidizes gold", "HCl alone dissolves gold", "Heat dissolves gold"], ans: 0, exp: "Aqua regia (3 HCl : 1 HNO₃): HNO₃ oxidizes Au to Au³⁺; HCl provides Cl⁻ → [AuCl₄]⁻ (tetrachloroaurate complex) → increases thermodynamic driving force. Neither acid alone dissolves gold. NCERT Class 12, Ch 6.", stars: 5 },
  { id: 106, subject: "Chemistry", section: "Inorganic", q: "Hydrogen fluoride (HF) has a higher boiling point than HCl despite lower molecular weight because:", options: ["HF is an acid", "HF has strong hydrogen bonding between F atoms (highly electronegative)", "HF is heavier", "HF has more electrons"], ans: 1, exp: "HF has anomalously high boiling point (19.5°C vs −85°C for HCl) due to STRONG hydrogen bonding (F is most electronegative element). HF forms zigzag chains (HF)n via H-bonds. This is an anomalous property of HF. NCERT Class 11, Ch 9.", stars: 4 },
  { id: 107, subject: "Chemistry", section: "Inorganic", q: "The chemical species responsible for the blue colour of sky is the phenomenon of:", options: ["Reflection", "Tyndall effect (colloidal scattering)", "Refraction", "Absorption"], ans: 1, exp: "Blue sky: Tyndall effect — colloidal dust/water particles in atmosphere scatter blue light (shorter wavelength scattered more). Sunrise/sunset: red/orange light (longer wavelength less scattered, passes through more atmosphere). NCERT Class 12, Ch 5.", stars: 4 },
  { id: 108, subject: "Chemistry", section: "Physical", q: "In an ideal solution, which of the following is zero?", options: ["Vapour pressure", "ΔHmix and ΔVmix (no enthalpy or volume change on mixing)", "Entropy", "Osmotic pressure"], ans: 1, exp: "Ideal solution: obeys Raoult's law for all concentrations. ΔHmix = 0 (solute-solvent interactions = solute-solute + solvent-solvent). ΔVmix = 0. Examples: benzene-toluene, n-hexane-n-heptane. Non-ideal: shows positive or negative deviations. NCERT Class 12, Ch 2.", stars: 5 },
  { id: 109, subject: "Chemistry", section: "Physical", q: "The activation energy (Ea) of a reaction can be calculated using:", options: ["Rate law", "Arrhenius equation: ln k = ln A − Ea/RT", "Equilibrium constant", "Half-life formula"], ans: 1, exp: "Arrhenius equation: k = Ae^(−Ea/RT). Linear form: ln k = ln A − Ea/RT. Plot of ln k vs 1/T → slope = −Ea/R → Ea = −slope × R. A = frequency factor (pre-exponential factor, related to collision frequency). NCERT Class 12, Ch 4.", stars: 5 },
  { id: 110, subject: "Chemistry", section: "Physical", q: "Le Chatelier's principle states that:", options: ["A reaction goes to completion always", "A system in equilibrium, when disturbed, shifts to minimize the disturbance", "Increasing temperature always increases yield", "Catalyst changes equilibrium position"], ans: 1, exp: "Le Chatelier's principle: when a system at equilibrium is stressed (change in concentration, pressure, temperature), it shifts in the direction that partially counteracts the change. Catalyst: speeds up equilibrium but does NOT change Keq or equilibrium position. NCERT Class 11, Ch 7.", stars: 5 },
  { id: 111, subject: "Chemistry", section: "Physical", q: "Which of the following is an extensive property?", options: ["Density", "Temperature", "Internal energy (U)", "Refractive index"], ans: 2, exp: "Extensive properties: depend on amount of matter (size of system). Examples: mass, volume, energy (internal, enthalpy, entropy), heat capacity. Intensive properties: do NOT depend on amount. Examples: density, temperature, refractive index, molar properties. NCERT Class 11, Ch 6.", stars: 4 },
  { id: 112, subject: "Chemistry", section: "Organic", q: "The Bayer strain theory explains the instability of cyclopropane due to:", options: ["Torsional strain", "Ring strain due to deviation of bond angles from 109.5° (angle strain)", "Steric strain", "Electronic repulsion"], ans: 1, exp: "Baeyer strain theory: cyclopropane (60° angles) has maximum deviation from tetrahedral 109.5° → highest ring strain (angle strain). Cyclobutane: 90°. Cyclopentane: ~108° (least strain). Cyclohexane: chair conformation, 109.5° angles, no ring strain. NCERT Class 11, Ch 13.", stars: 4 },
  { id: 113, subject: "Chemistry", section: "Organic", q: "Which of the following correctly describes a nucleophile?", options: ["Electron pair acceptor", "Electron pair donor (Lewis base), attacks electron-deficient centres", "Proton donor", "Radical species"], ans: 1, exp: "Nucleophile (nucleus-lover): electron pair donor = Lewis base. Attacks electron-deficient carbon. Examples: OH⁻, CN⁻, NH₃, Br⁻, H₂O. Electrophile (electron-lover): electron pair acceptor = Lewis acid. Examples: H⁺, Br⁺, NO₂⁺, carbocations. NCERT Class 11, Ch 12.", stars: 5 },
  { id: 114, subject: "Chemistry", section: "Organic", q: "Rosenmund reduction converts acid chloride (RCOCl) to:", options: ["Carboxylic acid", "Aldehyde (RCHO)", "Alcohol", "Ketone"], ans: 1, exp: "Rosenmund reduction: RCOCl + H₂ (Pd/BaSO₄ catalyst, poisoned) → RCHO (aldehyde). The catalyst is 'poisoned' (deactivated) to prevent further reduction to alcohol. Stephen's reduction: nitrile → aldehyde. NCERT Class 12, Ch 12.", stars: 5 },
  { id: 115, subject: "Chemistry", section: "Organic", q: "The product of ozonolysis of propene followed by reductive workup is:", options: ["CO₂ and propan-1-ol", "Formaldehyde + ethanal (HCHO + CH₃CHO)", "Propanone", "Propan-2-ol"], ans: 1, exp: "Ozonolysis of propene (CH₃-CH=CH₂): O₃ cleaves the double bond. Reductive workup (Zn/H₂O or PPh₃): gives two carbonyl compounds. CH₂= → HCHO (formaldehyde) + CH₃CH= → CH₃CHO (acetaldehyde). NCERT Class 11, Ch 13.", stars: 5 },
  { id: 116, subject: "Chemistry", section: "Inorganic", q: "The magnetic moment of a d⁵ high-spin complex is:", options: ["0 BM", "1.73 BM", "3.87 BM", "5.92 BM"], ans: 3, exp: "Magnetic moment μ = √(n(n+2)) BM, where n = unpaired electrons. d⁵ high-spin: 5 unpaired electrons. μ = √(5×7) = √35 ≈ 5.92 BM. Example: Mn²⁺ and Fe³⁺ (d⁵, high-spin in weak field). NCERT Class 12, Ch 9.", stars: 5 },
  { id: 117, subject: "Chemistry", section: "Inorganic", q: "The correct order of first ionization enthalpy for Be, B, N, O is:", options: ["B > Be > N > O", "N > O > Be > B", "Be > B < N > O", "Be < B < N < O"], ans: 2, exp: "First IE trend: increases across period but with exceptions. B < Be (B's 2p¹ less stable than Be's 2s² due to penetration). O < N (N has half-filled 2p³, extra stability; O's 2p⁴ has electron-electron repulsion). Order: B < Be < O < N. NCERT Class 11, Ch 3.", stars: 5 },
  { id: 118, subject: "Chemistry", section: "Physical", q: "The Freundlich adsorption isotherm is given by:", options: ["x/m = k·p", "x/m = k·p^(1/n) (n > 1)", "x/m = Kp/(1+Kp)", "x/m = k·p²"], ans: 1, exp: "Freundlich adsorption isotherm: x/m = k·p^(1/n) where 1/n is between 0 and 1, k and n are Freundlich constants. Log(x/m) = log k + (1/n)log p (linear plot). Langmuir isotherm: x/m = Kp/(1+Kp). NCERT Class 12, Ch 5.", stars: 4 },
  { id: 119, subject: "Chemistry", section: "Physical", q: "Kohlrausch's law of independent migration of ions states that:", options: ["Conductivity depends on current", "Limiting molar conductivity of an electrolyte = sum of limiting molar conductivities of its ions", "All electrolytes conduct equally", "Conductivity increases with concentration"], ans: 1, exp: "Kohlrausch's law: Λ°m = ν₊λ°₊ + ν₋λ°₋. Used to calculate Λ°m of weak electrolytes (which cannot be determined directly by extrapolation). Example: Λ°m(CH₃COOH) = Λ°m(CH₃COONa) + Λ°m(HCl) − Λ°m(NaCl). NCERT Class 12, Ch 3.", stars: 4 },
  { id: 120, subject: "Chemistry", section: "Physical", q: "For a reaction at equilibrium, the relationship between Kp and Kc is:", options: ["Kp = Kc + RT", "Kp = Kc (RT)^Δn", "Kp = Kc/RT", "Kp = Kc²"], ans: 1, exp: "Kp = Kc (RT)^Δn, where Δn = (moles of gaseous products − moles of gaseous reactants). If Δn = 0: Kp = Kc. If Δn > 0: Kp > Kc. R = 0.0821 L·atm/K·mol, T in Kelvin. NCERT Class 11, Ch 7.", stars: 5 },
  { id: 121, subject: "Chemistry", section: "Inorganic", q: "Phosphorus forms PCl₅ but nitrogen does NOT form NCl₅ because:", options: ["N is a non-metal", "N lacks d-orbitals in valence shell (cannot expand octet)", "PCl₅ is ionic", "N is too large"], ans: 1, exp: "Nitrogen (Period 2): maximum covalence = 4 (no d-orbitals available). Cannot expand octet. Phosphorus (Period 3): has vacant 3d orbitals → can expand octet → PCl₅ possible. Also explains why P forms H₃PO₄ (P=O using d-orbitals) but N forms HNO₃ differently. NCERT Class 12, Ch 7.", stars: 5 },
  { id: 122, subject: "Chemistry", section: "Inorganic", q: "The ore of aluminium is:", options: ["Haematite", "Magnetite", "Bauxite (Al₂O₃·2H₂O)", "Cassiterite"], ans: 2, exp: "Ores: Aluminium → Bauxite (Al₂O₃·2H₂O) → Hall-Heroult process (electrolytic reduction). Iron → Haematite (Fe₂O₃), Magnetite (Fe₃O₄) → Blast furnace. Copper → Copper pyrites (CuFeS₂). Tin → Cassiterite (SnO₂). NCERT Class 12, Ch 6.", stars: 4 },
  { id: 123, subject: "Chemistry", section: "Organic", q: "The product of the reaction of an amine with an acyl chloride is:", options: ["Amide", "Salt (hydrochloride)", "Nitrile", "Imine"], ans: 0, exp: "Acylation of amines: R-NH₂ + RCOCl → RCONHR + HCl (amide = Schotten-Baumann reaction). Uses: synthesis of amides, Nylon (polyamide). The reaction is done with pyridine to absorb HCl. NCERT Class 12, Ch 13.", stars: 4 },
  { id: 124, subject: "Chemistry", section: "Physical", q: "The molal depression constant (Kf) for water is:", options: ["0.52 K·kg/mol", "1.86 K·kg/mol", "3.9 K·kg/mol", "2.0 K·kg/mol"], ans: 1, exp: "Cryoscopic constants (Kf): Water = 1.86 K·kg/mol, Benzene = 5.12, Acetic acid = 3.9. Ebullioscopic constants (Kb): Water = 0.52 K·kg/mol, Benzene = 2.53. ΔTf = Kf × m, ΔTb = Kb × m. NCERT Class 12, Ch 2.", stars: 5 },
  { id: 125, subject: "Chemistry", section: "Organic", q: "The functional group present in Bakelite is:", options: ["Ester", "Ether", "Methylene bridge (−CH₂−) connecting benzene rings", "Amide"], ans: 2, exp: "Bakelite: thermosetting polymer. Condensation of phenol + formaldehyde → 3D cross-linked network via methylene (−CH₂−) bridges. Used in electrical fittings, utensils. Melamine formaldehyde resin: similar structure, used in floor tiles, kitchenware. NCERT Class 12, Ch 15.", stars: 4 },
  { id: 126, subject: "Chemistry", section: "Physical", q: "The first law of thermodynamics can be expressed as:", options: ["ΔU = q − w (work done BY the system)", "ΔU = q + w (work done ON the system)", "Both A and B depending on convention", "ΔH = ΔU"], ans: 2, exp: "First Law: Conservation of energy. ΔU = q − w (IUPAC: w = work done BY system; if system expands against pressure). OR ΔU = q + w (w = work done ON system). Both are correct — depends on sign convention. NCERT Class 11, Ch 6.", stars: 4 },
  { id: 127, subject: "Chemistry", section: "Organic", q: "In the Williamson synthesis, ethers are prepared by:", options: ["Dehydration of alcohols", "Reaction of alkyl halide with sodium alkoxide (R-X + NaOR' → ROR' + NaX)", "Reaction of two alcohols", "Oxidation of alcohols"], ans: 1, exp: "Williamson ether synthesis: SN2 reaction. Sodium alkoxide (NaOR') + Primary alkyl halide (R-X) → Ether (R-O-R') + NaX. Must use primary alkyl halide (secondary/tertiary → elimination instead). Used for both symmetrical and mixed ethers. NCERT Class 12, Ch 11.", stars: 5 },
  { id: 128, subject: "Chemistry", section: "Inorganic", q: "The process of electrolytic refining of copper uses:", options: ["Copper cathode, impure copper anode", "Impure copper cathode, pure copper anode", "Impure copper anode, pure copper cathode", "Both electrodes pure"], ans: 2, exp: "Electrolytic refining: Impure metal = anode, Pure metal = cathode, same metal salt = electrolyte. Anode dissolves, pure metal deposits at cathode. Anode mud: contains noble metals (Au, Ag, Pt). Used for Cu, Ag, Au, Al refining. NCERT Class 12, Ch 6.", stars: 5 },
  { id: 129, subject: "Chemistry", section: "Physical", q: "The number of atoms in 1 mole of oxygen gas (O₂) is:", options: ["6.022 × 10²³", "1.204 × 10²⁴ (2 × Avogadro's number)", "3 × 10²³", "Avogadro's number of molecules"], ans: 1, exp: "1 mol O₂: 6.022 × 10²³ molecules (Avogadro's number N_A). Each O₂ has 2 atoms. ∴ atoms = 2 × 6.022 × 10²³ = 1.204 × 10²⁴. NCERT Class 11, Ch 1.", stars: 4 },
  { id: 130, subject: "Chemistry", section: "Organic", q: "Which of the following is the strongest acid?", options: ["CH₃COOH (acetic acid)", "Cl₂CHCOOH (dichloroacetic acid)", "ClCH₂COOH (chloroacetic acid)", "CCl₃COOH (trichloroacetic acid)"], ans: 3, exp: "Inductive effect: electron-withdrawing groups (-I effect) increase acidity by stabilizing carboxylate anion. More Cl atoms → stronger -I effect → more stable anion → stronger acid. Order: CCl₃COOH > Cl₂CHCOOH > ClCH₂COOH > CH₃COOH. NCERT Class 12, Ch 12.", stars: 5 },
  { id: 131, subject: "Chemistry", section: "Organic", q: "The reaction of benzene with chlorine in presence of anhydrous AlCl₃ gives:", options: ["Cyclohexane", "Chlorobenzene (via electrophilic aromatic substitution)", "Benzene diazonium chloride", "Benzaldehyde"], ans: 1, exp: "Friedel-Crafts halogenation: C₆H₆ + Cl₂ (anhydrous AlCl₃) → C₆H₅Cl (chlorobenzene) + HCl. AlCl₃ is Lewis acid catalyst → generates Cl⁺ (electrophile) → EAS. Sunlight (no catalyst): free radical substitution → chlorocyclohexane. NCERT Class 11, Ch 13.", stars: 5 },
  { id: 132, subject: "Chemistry", section: "Inorganic", q: "Which of the following has the highest oxidizing power among halogens?", options: ["F₂", "Cl₂", "Br₂", "I₂"], ans: 0, exp: "Oxidizing power of halogens: F₂ > Cl₂ > Br₂ > I₂ (decreases down the group). F₂ is the strongest oxidizing agent (most electronegative, smallest, highest electrode potential E° = +2.87V). Can oxidize Cl⁻ to Cl₂, Br⁻ to Br₂, I⁻ to I₂. NCERT Class 12, Ch 7.", stars: 4 },
  { id: 133, subject: "Chemistry", section: "Physical", q: "The entropy (S) of a perfectly crystalline substance at absolute zero (0 K) is:", options: ["Infinity", "Negative", "Zero (Third Law of Thermodynamics)", "Maximum"], ans: 2, exp: "Third Law of Thermodynamics (Nernst): S = 0 for a perfect crystal at 0 K (only one possible microstate, W = 1, S = k ln W = 0). Entropy is a measure of disorder/randomness. Spontaneous processes: ΔS_universe > 0. NCERT Class 11, Ch 6.", stars: 4 },
  { id: 134, subject: "Chemistry", section: "Organic", q: "Which polymer is an example of addition polymer?", options: ["Nylon-6,6", "Dacron (Terylene)", "Polyethylene (polythene)", "Bakelite"], ans: 2, exp: "Addition polymers: formed by addition of monomers without loss of any small molecule. Examples: Polyethylene (ethylene), PVC (vinyl chloride), Polystyrene (styrene), Teflon (tetrafluoroethylene). Condensation polymers: Nylon-6,6, Dacron, Bakelite (lose H₂O or HCl). NCERT Class 12, Ch 15.", stars: 4 },
  { id: 135, subject: "Chemistry", section: "Inorganic", q: "The geometry of [Ni(CN)₄]²⁻ is:", options: ["Tetrahedral", "Square planar (due to CN⁻ strong field ligand, Ni²⁺: d⁸ with pairing)", "Octahedral", "Linear"], ans: 1, exp: "[Ni(CN)₄]²⁻: Ni²⁺ = d⁸. CN⁻ is strong field ligand → pairing of electrons → d²sp³? No: dsp² hybridization → square planar. Strong field → low spin d⁸ → dsp² → square planar (diamagnetic). Compare with [NiCl₄]²⁻: Cl⁻ weak field → sp³ → tetrahedral (paramagnetic). NCERT Class 12, Ch 9.", stars: 5 },
  // PHYSICS (136-180)
  { id: 136, subject: "Physics", section: "Mechanics", q: "A body is moving in a circle of radius r with constant speed. The acceleration is directed:", options: ["Tangentially", "Away from centre", "Towards the centre (centripetal)", "At 45° to radius"], ans: 2, exp: "Uniform circular motion: speed is constant but direction changes → centripetal acceleration a = v²/r = ω²r directed towards the centre. Net force = centripetal force F = mv²/r (provided by tension, gravity, normal force, friction depending on context). NCERT Class 11, Ch 4.", stars: 5 },
  { id: 137, subject: "Physics", section: "Mechanics", q: "The angle of projection for maximum horizontal range of a projectile is:", options: ["30°", "60°", "45°", "90°"], ans: 2, exp: "Projectile motion: Range R = u²sin2θ/g. R is maximum when sin2θ = 1 → 2θ = 90° → θ = 45°. Max range = u²/g. At θ = 30° and 60°: same range (complementary angles). Time of flight T = 2u sinθ/g. NCERT Class 11, Ch 4.", stars: 5 },
  { id: 138, subject: "Physics", section: "Mechanics", q: "The moment of inertia of a thin rod of mass M and length L about its centre perpendicular to its length is:", options: ["ML²/3", "ML²/12", "ML²/4", "ML²/6"], ans: 1, exp: "Moment of inertia (I): Thin rod about centre = ML²/12. About end = ML²/3. Solid disc about axis = MR²/2. Solid sphere = 2MR²/5. Hollow sphere = 2MR²/3. Ring about axis = MR². Parallel axis theorem: I = Icm + Md². NCERT Class 11, Ch 7.", stars: 5 },
  { id: 139, subject: "Physics", section: "Thermodynamics", q: "The efficiency of a Carnot engine working between temperatures T₁ (hot) and T₂ (cold) is:", options: ["η = T₂/T₁", "η = 1 − T₂/T₁", "η = (T₁−T₂)/T₂", "η = T₁/T₂"], ans: 1, exp: "Carnot efficiency: η = 1 − T₂/T₁ = (T₁−T₂)/T₁. This is the MAXIMUM possible efficiency for any heat engine operating between these temperatures (Second Law). Cannot be 100% unless T₂ = 0 K (impossible). NCERT Class 11, Ch 12.", stars: 5 },
  { id: 140, subject: "Physics", section: "Waves", q: "The speed of sound in air at temperature T (Kelvin) is proportional to:", options: ["T", "T²", "√T", "1/√T"], ans: 2, exp: "Speed of sound in gas: v = √(γRT/M). v ∝ √T (absolute temperature). At 0°C: 331 m/s, at 20°C: 343 m/s. v increases with temperature (increases by ~0.6 m/s per °C). v doesn't depend on pressure (at constant T). NCERT Class 11, Ch 15.", stars: 5 },
  { id: 141, subject: "Physics", section: "Electricity", q: "Coulomb's law gives the force between two charges q₁ and q₂ separated by distance r as:", options: ["F = kq₁q₂/r", "F = kq₁q₂/r²", "F = kq₁q₂r²", "F = kq₁q₂/r³"], ans: 1, exp: "Coulomb's law: F = kq₁q₂/r² = q₁q₂/(4πε₀r²). k = 9×10⁹ N·m²/C². ε₀ = 8.854×10⁻¹² C²/N·m² (permittivity of free space). Like charges repel, unlike attract. F is vector (along line joining charges). NCERT Class 12, Ch 1.", stars: 5 },
  { id: 142, subject: "Physics", section: "Electricity", q: "The drift velocity of electrons in a conductor is related to current by:", options: ["I = nAevd (directly proportional to drift velocity)", "I = nAe/vd", "I = nA/evd", "I = nAvd"], ans: 0, exp: "I = nAevd. n = number density of free electrons, A = cross-sectional area, e = electron charge, vd = drift velocity. Drift velocity is very small (~10⁻³ m/s), but current is large because n is huge (~10²⁸/m³). NCERT Class 12, Ch 3.", stars: 5 },
  { id: 143, subject: "Physics", section: "Electricity", q: "In a parallel plate capacitor, the capacitance is given by:", options: ["C = εA/d", "C = ε₀A/d", "C = ε₀A/d (for vacuum/air)", "C = ε₀εrA/d (with dielectric εr)"], ans: 3, exp: "Capacitance: C = ε₀A/d (vacuum). With dielectric: C = ε₀εrA/d = Kε₀A/d (K = dielectric constant = εr). Capacitance increases by factor K with dielectric. Energy stored: U = Q²/2C = CV²/2 = QV/2. NCERT Class 12, Ch 2.", stars: 5 },
  { id: 144, subject: "Physics", section: "Magnetism", q: "The force on a current-carrying conductor in a magnetic field is given by:", options: ["F = qE", "F = IL × B (F = BIL sinθ)", "F = qvB", "F = IL/B"], ans: 1, exp: "Force on current-carrying conductor: F = IL × B (vector form). Magnitude: F = BIL sinθ. If θ = 90° (B⊥L): F = BIL (maximum). θ = 0° (B∥L): F = 0. This is the basis of DC motors. NCERT Class 12, Ch 4.", stars: 5 },
  { id: 145, subject: "Physics", section: "Optics", q: "The critical angle (θc) for total internal reflection is related to refractive index by:", options: ["sinθc = n", "sinθc = 1/n (n = refractive index of denser medium)", "sinθc = n²", "cosθc = 1/n"], ans: 1, exp: "Critical angle: sinθc = 1/n = n₂/n₁ (for going from denser to rarer medium). TIR occurs when θ > θc. Applications: optical fibres, prism reflectors, diamonds (high n → small θc → brilliant sparkling). NCERT Class 12, Ch 9.", stars: 5 },
  { id: 146, subject: "Physics", section: "Optics", q: "A convex lens of focal length f forms a real image when the object is placed at:", options: ["Between F and 2F", "Beyond 2F", "Between F and optical centre", "All of the above (A and B)"], ans: 3, exp: "Convex lens: Object beyond F → real, inverted image on other side. Object between F and lens → virtual, erect, magnified image on same side as object (works as magnifying glass). At 2F: image at 2F, same size. Beyond 2F: image between F and 2F, smaller. NCERT Class 12, Ch 9.", stars: 4 },
  { id: 147, subject: "Physics", section: "Modern Physics", q: "According to de Broglie, a particle of mass m moving with velocity v has wavelength:", options: ["λ = mv/h", "λ = h/mv", "λ = h·mv", "λ = h/mv²"], ans: 1, exp: "de Broglie wavelength: λ = h/mv = h/p (p = momentum). Wave-particle duality: every particle has a corresponding wave. Confirmed by Davisson-Germer experiment (electron diffraction). Heavier particles have smaller wavelengths. NCERT Class 12, Ch 11.", stars: 5 },
  { id: 148, subject: "Physics", section: "Modern Physics", q: "Radioactive decay follows first-order kinetics. The half-life (T₁/₂) is related to decay constant (λ) by:", options: ["T₁/₂ = λ/0.693", "T₁/₂ = 0.693/λ", "T₁/₂ = 1/λ", "T₁/₂ = λ × 0.693"], ans: 1, exp: "Radioactive decay: N = N₀e^(−λt). Half-life: T₁/₂ = 0.693/λ = (ln2)/λ. Mean life (τ) = 1/λ = T₁/₂/0.693 = 1.44 T₁/₂. After n half-lives: N = N₀/2ⁿ. NCERT Class 12, Ch 13.", stars: 5 },
  { id: 149, subject: "Physics", section: "Electricity", q: "The resistance of a conductor of length L, cross-sectional area A, and resistivity ρ is:", options: ["R = ρA/L", "R = ρL/A", "R = ρL·A", "R = ρ/LA"], ans: 1, exp: "Resistance: R = ρL/A. ρ (resistivity) depends on material and temperature. Good conductors: low ρ. Insulators: high ρ. Semiconductors: intermediate. R increases with temperature for metals (positive temperature coefficient). NCERT Class 12, Ch 3.", stars: 5 },
  { id: 150, subject: "Physics", section: "Thermodynamics", q: "According to Kirchhoff's law of radiation, good absorbers are also:", options: ["Good reflectors", "Good emitters", "Bad emitters", "Transparent to all radiation"], ans: 1, exp: "Kirchhoff's law of radiation: at thermal equilibrium, emissivity = absorptivity (e = a). Good absorbers = good emitters. Perfect blackbody: absorbs all radiation, emits maximally. Lampblack (coal): e ≈ 1 (near perfect blackbody). NCERT Class 11, Ch 11.", stars: 4 },
  { id: 151, subject: "Physics", section: "Mechanics", q: "The escape velocity from Earth's surface is approximately:", options: ["7.9 km/s", "11.2 km/s", "3 km/s", "30 km/s"], ans: 1, exp: "Escape velocity: ve = √(2GM/R) = √(2gR) ≈ 11.2 km/s. Orbital velocity (for near-Earth orbit): vo = √(GM/R) = √(gR) ≈ 7.9 km/s. ve = √2 × vo. Energy for escape = ½mve² = GMm/R. NCERT Class 11, Ch 8.", stars: 5 },
  { id: 152, subject: "Physics", section: "Mechanics", q: "Kepler's third law (law of periods) states:", options: ["Planets move in elliptical orbits", "Equal areas swept in equal times", "T² ∝ a³ (square of period ∝ cube of semi-major axis)", "Orbits are perfectly circular"], ans: 2, exp: "Kepler's Laws: 1st: Elliptical orbits, Sun at focus. 2nd: Equal areas swept in equal times (areal velocity = constant → angular momentum conservation). 3rd: T² = (4π²/GM)a³ → T² ∝ a³. NCERT Class 11, Ch 8.", stars: 5 },
  { id: 153, subject: "Physics", section: "Optics", q: "Polarization of light proves that light is a:", options: ["Longitudinal wave", "Transverse wave", "Standing wave", "Mechanical wave"], ans: 1, exp: "Polarization: only transverse waves can be polarized (oscillations confined to one plane). Light is a transverse EM wave (E and B fields perpendicular to propagation). Longitudinal waves (sound) cannot be polarized. Polaroids: used in sunglasses, LCD screens, photography. NCERT Class 12, Ch 10.", stars: 5 },
  { id: 154, subject: "Physics", section: "Modern Physics", q: "The photoelectric effect is explained by Einstein using the concept of:", options: ["Wave nature of light", "Photon (quantum of light energy E = hf)", "Interference", "Diffraction"], ans: 1, exp: "Einstein's photoelectric equation: KE_max = hf − φ (φ = work function). Key observations: (1) Threshold frequency exists, (2) KE independent of intensity, (3) Instantaneous emission. Einstein won Nobel 1921 for this explanation. NCERT Class 12, Ch 11.", stars: 5 },
  { id: 155, subject: "Physics", section: "Electricity", q: "In a full-wave rectifier using two diodes and a centre-tapped transformer, the ripple frequency is:", options: ["Equal to input frequency (f)", "Double the input frequency (2f)", "Half the input frequency", "Zero"], ans: 1, exp: "Full-wave rectifier: both half-cycles of AC are rectified. Ripple frequency = 2f (100 Hz for 50 Hz supply). Half-wave rectifier: only one half-cycle → ripple frequency = f (50 Hz). Bridge rectifier (4 diodes): also 2f. NCERT Class 12, Ch 14.", stars: 4 },
  { id: 156, subject: "Physics", section: "Magnetism", q: "The magnetic field at the centre of a circular loop of radius R carrying current I is:", options: ["B = μ₀I/2R", "B = μ₀I/4πR", "B = μ₀I/2πR", "B = μ₀IR"], ans: 0, exp: "Magnetic field at centre of circular loop: B = μ₀I/2R. For long straight wire: B = μ₀I/2πr. For solenoid: B = μ₀nI. Toroid: B = μ₀nI (n = N/2πR, N = total turns). NCERT Class 12, Ch 4.", stars: 5 },
  { id: 157, subject: "Physics", section: "Optics", q: "The resolving power of a microscope depends on:", options: ["Focal length of eyepiece", "Wavelength of light used (shorter λ = better resolution)", "Magnification only", "Length of tube"], ans: 1, exp: "Resolving power: minimum resolvable distance (d) = 0.61λ/μsinθ (Rayleigh criterion). Shorter wavelength → better resolution. Electron microscope uses electron waves (λ ~0.004 nm) → much better resolution than optical. NCERT Class 12, Ch 9.", stars: 4 },
  { id: 158, subject: "Physics", section: "Thermodynamics", q: "The specific heat capacity of a monoatomic ideal gas at constant volume (Cv) is:", options: ["R", "3R/2", "5R/2", "7R/2"], ans: 1, exp: "Monoatomic ideal gas (He, Ne, Ar): 3 translational degrees of freedom. Cv = (f/2)R = 3R/2 = 12.47 J/mol/K. Cp = Cv + R = 5R/2. γ = Cp/Cv = 5/3. Diatomic (N₂, O₂): Cv = 5R/2, Cp = 7R/2, γ = 7/5. NCERT Class 11, Ch 13.", stars: 5 },
  { id: 159, subject: "Physics", section: "Mechanics", q: "In simple harmonic motion (SHM), at the mean position:", options: ["Velocity = 0, acceleration = maximum", "Velocity = maximum, acceleration = 0", "Both velocity and acceleration = maximum", "Both velocity and acceleration = 0"], ans: 1, exp: "SHM: x = A sinωt, v = Aω cosωt, a = −Aω²sinωt. At mean position (x=0): v = Aω (maximum), a = 0. At extreme positions (x=±A): v = 0, a = ±Aω² (maximum). Restoring force F = −kx. NCERT Class 11, Ch 14.", stars: 5 },
  { id: 160, subject: "Physics", section: "Electricity", q: "In a step-up transformer, if input voltage is V₁ and output is V₂, and turns are N₁ and N₂, then:", options: ["V₁/V₂ = N₁/N₂", "V₂/V₁ = N₂/N₁ (V₂ > V₁ for N₂ > N₁)", "V₁N₁ = V₂N₂", "V₁ = V₂"], ans: 1, exp: "Ideal transformer: V₁/V₂ = N₁/N₂; I₁/I₂ = N₂/N₁ (power conserved: V₁I₁ = V₂I₂). Step-up: N₂ > N₁ → V₂ > V₁, but I₂ < I₁. Used to transmit electrical power over long distances at high voltage (low current → less I²R loss). NCERT Class 12, Ch 7.", stars: 5 },
  { id: 161, subject: "Physics", section: "Modern Physics", q: "Which series of hydrogen spectrum lies in the visible region?", options: ["Lyman series", "Balmer series (n→2 transitions)", "Paschen series", "Brackett series"], ans: 1, exp: "Hydrogen spectral series: Lyman (UV, n→1), Balmer (visible, n→2, 4 lines: violet, blue-green, blue, red), Paschen (IR, n→3), Brackett (IR, n→4), Pfund (far-IR, n→5). NCERT Class 12, Ch 12.", stars: 5 },
  { id: 162, subject: "Physics", section: "Mechanics", q: "A body at rest on a rough surface. The coefficient of static friction (μs) is related to the limiting friction force (fs) by:", options: ["fs = μsN (N = normal force)", "fs = N/μs", "fs = μsN²", "fs = μs/N"], ans: 0, exp: "Laws of friction: fs ≤ μsN (static friction up to limiting value). When moving: kinetic friction fk = μkN. μk < μs (easier to keep moving than to start). Rolling friction < kinetic friction < static friction. NCERT Class 11, Ch 5.", stars: 4 },
  { id: 163, subject: "Physics", section: "Electricity", q: "The electric potential V at a distance r from a point charge q is:", options: ["V = kq/r²", "V = kq/r", "V = kqr", "V = kq²/r"], ans: 1, exp: "Electric potential: V = kq/r = q/(4πε₀r). E = −dV/dr (field = −ve gradient of potential). For positive charge: V is positive, decreases with r. Equipotential surfaces: perpendicular to E field. Work done in moving charge on equipotential = 0. NCERT Class 12, Ch 2.", stars: 5 },
  { id: 164, subject: "Physics", section: "Mechanics", q: "The work-energy theorem states that the net work done on an object equals:", options: ["Its potential energy change", "Its change in kinetic energy (Wnet = ΔKE)", "Its total mechanical energy", "Its displacement times weight"], ans: 1, exp: "Work-energy theorem: Wnet = ΔKE = ½mv² − ½mv₀². This is a direct consequence of Newton's 2nd Law. Conservative forces: work done = − change in PE. Total mechanical energy = KE + PE = constant (if only conservative forces). NCERT Class 11, Ch 6.", stars: 5 },
  { id: 165, subject: "Physics", section: "Magnetism", q: "A galvanometer can be converted into a voltmeter by connecting:", options: ["A low resistance in parallel", "A high resistance in series", "A low resistance in series", "A high resistance in parallel"], ans: 1, exp: "Galvanometer conversions: Ammeter: low resistance (shunt S) in PARALLEL (divides current). Voltmeter: high resistance R in SERIES (reduces current for given voltage). R = V/Ig − G. Ideal voltmeter: infinite resistance (draws no current). NCERT Class 12, Ch 4.", stars: 5 },
  { id: 166, subject: "Physics", section: "Modern Physics", q: "In the Bohr model, the radius of the nth orbit of hydrogen atom is:", options: ["rn = n²a₀ (a₀ = 0.529 Å, Bohr radius)", "rn = na₀", "rn = n²/a₀", "rn = a₀/n²"], ans: 0, exp: "Bohr model: rn = n²a₀ (a₀ = 0.529 Å = Bohr radius for n=1). Energy En = −13.6/n² eV. Speed vn = v₁/n. Angular momentum: mvnrn = nℏ (quantized). r₂ = 4a₀, r₃ = 9a₀. NCERT Class 12, Ch 12.", stars: 5 },
  { id: 167, subject: "Physics", section: "Optics", q: "In total internal reflection in optical fibre, light travels by successive:", options: ["Refractions", "Reflections at core-cladding interface (core: higher n)", "Diffractions", "Absorptions and emissions"], ans: 1, exp: "Optical fibre: light enters core (higher refractive index) → hits core-cladding interface at angle > critical angle → TIR → light trapped and travels through fibre. Used in: communication (telephone, internet), medical endoscopy. NCERT Class 12, Ch 9.", stars: 5 },
  { id: 168, subject: "Physics", section: "Electricity", q: "Kirchhoff's current law (KCL) is based on conservation of:", options: ["Energy", "Charge (sum of currents at junction = 0)", "Momentum", "Mass"], ans: 1, exp: "Kirchhoff's Laws: KCL (Junction rule): ΣI_in = ΣI_out (conservation of charge). KVL (Loop rule): Sum of EMFs = sum of potential drops = Σ(IR) (conservation of energy). Both laws apply to any circuit. NCERT Class 12, Ch 3.", stars: 5 },
  { id: 169, subject: "Physics", section: "Waves", q: "The phenomenon of beats is caused by:", options: ["Reflection of sound", "Superposition of two waves with slightly different frequencies", "Standing waves", "Resonance"], ans: 1, exp: "Beats: when two sound waves of slightly different frequencies (f₁ and f₂) superpose → periodic variation in loudness. Beat frequency = |f₁ − f₂|. Used to tune musical instruments. NCERT Class 11, Ch 15.", stars: 4 },
  { id: 170, subject: "Physics", section: "Mechanics", q: "For an elastic collision between two objects, which quantities are conserved?", options: ["Momentum only", "Kinetic energy only", "Both momentum AND kinetic energy", "Potential energy only"], ans: 2, exp: "Elastic collision: both momentum AND kinetic energy conserved. Perfectly inelastic: momentum conserved, KE NOT conserved (maximum KE lost). For equal masses in elastic collision: velocities exchange. Real-world: billiard balls (approximately elastic). NCERT Class 11, Ch 6.", stars: 5 },
  { id: 171, subject: "Physics", section: "Mechanics", q: "Newton's second law of motion states that:", options: ["F = mv (momentum only)", "F = ma (net force = mass × acceleration) or F = dp/dt", "Action and reaction are equal and opposite", "Inertia determines motion"], ans: 1, exp: "Newton's 2nd Law: F_net = ma = dp/dt (rate of change of momentum). Most important form: F = dp/dt. For constant mass: F = ma. 1st Law: body at rest/constant velocity if no net force (inertia). 3rd Law: action = −reaction (equal, opposite, on different bodies). NCERT Class 11, Ch 5.", stars: 4 },
  { id: 172, subject: "Physics", section: "Waves", q: "Standing waves in a string fixed at both ends have nodes at the ends. The fundamental frequency is:", options: ["v/L", "v/2L", "v/4L", "2v/L"], ans: 1, exp: "Fundamental (1st harmonic): λ₁ = 2L → f₁ = v/2L. 2nd harmonic: f₂ = v/L = 2f₁. 3rd harmonic: f₃ = 3v/2L. Open organ pipe: f₁ = v/2L (both ends open, same as string). Closed organ pipe: f₁ = v/4L (only odd harmonics). NCERT Class 11, Ch 15.", stars: 4 },
  { id: 173, subject: "Physics", section: "Modern Physics", q: "According to the Heisenberg uncertainty principle:", options: ["Position and velocity can be determined simultaneously", "Δx × Δp ≥ h/4π", "Δx × Δp = h", "Only energy is uncertain"], ans: 1, exp: "Heisenberg uncertainty principle: Δx × Δp ≥ h/4π (ℏ/2). Also: ΔE × Δt ≥ h/4π. Fundamental limitation — not due to instrument error but quantum nature. An electron cannot have zero energy (zero-point energy). Explains stability of atoms. NCERT Class 11, Ch 2.", stars: 4 },
  { id: 174, subject: "Physics", section: "Electricity", q: "An electric field E and a magnetic field B act at right angles. The particle moves undeviated if:", options: ["E = B", "v = E/B", "v = B/E", "v = EB"], ans: 1, exp: "Velocity selector: For undeviated motion, electric force = magnetic force. qE = qvB → v = E/B. This condition selects only particles with velocity v = E/B regardless of their mass or charge (used in mass spectrometer). NCERT Class 12, Ch 4.", stars: 4 },
  { id: 175, subject: "Physics", section: "Electronics", q: "The energy gap (band gap) in a conductor, semiconductor and insulator respectively is:", options: ["Large, small, zero", "Zero, small (~1 eV), large (> 3 eV)", "Small, large, zero", "All equal"], ans: 1, exp: "Band theory: Conductor: conduction band and valence band overlap → Eg ≈ 0. Semiconductor: Eg ≈ 0.7 eV (Ge), 1.1 eV (Si). Insulator: Eg > 3 eV (diamond = 5.4 eV, SiO₂ = 9 eV). NCERT Class 12, Ch 14.", stars: 4 },
  { id: 176, subject: "Physics", section: "Thermodynamics", q: "The critical temperature of a gas is the temperature:", options: ["At which it solidifies", "Above which it cannot be liquefied by pressure alone", "At which it becomes superconducting", "At which its volume is minimum"], ans: 1, exp: "Critical temperature (Tc): above Tc, gas cannot be liquefied regardless of how much pressure is applied. For liquefaction, temperature must be below Tc. Tc for CO₂ = 31.1°C, O₂ = −118.4°C, N₂ = −147.1°C. NCERT Class 11, Ch 5.", stars: 4 },
  { id: 177, subject: "Physics", section: "Waves", q: "Electromagnetic waves: the correct relationship between E, B, and direction of propagation (k) is:", options: ["E ∥ B ∥ k", "E ⊥ B, both ⊥ k", "E ∥ k, B ⊥ k", "E ⊥ k, B ∥ k"], ans: 1, exp: "EM waves: E ⊥ B (mutually perpendicular electric and magnetic fields), and both ⊥ to direction of propagation (k). E × B gives the direction of propagation (Poynting vector S = E × B/µ₀). Speed c = E/B = 1/√(µ₀ε₀) ≈ 3×10⁸ m/s. NCERT Class 12, Ch 8.", stars: 4 },
  { id: 178, subject: "Physics", section: "Electronics", q: "For an n-p-n transistor in the active region (common emitter), the current gain β is defined as:", options: ["IC/IE", "IC/IB", "IB/IE", "IE/IC"], ans: 1, exp: "Transistor current relations: IE = IC + IB. β (common emitter current gain) = IC/IB (typically 20–500). α (common base) = IC/IE. Relationship: β = α/(1−α). In active region: emitter-base forward biased, collector-base reverse biased. Used as amplifier. NCERT Class 12, Ch 14.", stars: 4 },
  { id: 179, subject: "Physics", section: "Modern Physics", q: "An electron in hydrogen atom transitions from n=3 to n=1. The energy of photon emitted is: (E₁ = −13.6 eV)", options: ["12.09 eV", "13.6 eV", "1.51 eV", "10.2 eV"], ans: 0, exp: "E_n = −13.6/n² eV. E₃ = −13.6/9 = −1.51 eV. E₁ = −13.6/1 = −13.6 eV. ΔE = E₃ − E₁ = −1.51 − (−13.6) = 12.09 eV (photon energy emitted). This belongs to Lyman series (UV). n=3→2: Balmer (visible, 1.89 eV). NCERT Class 12, Ch 12.", stars: 5 },
  { id: 180, subject: "Physics", section: "Electricity", q: "In Ampere's law, the line integral of B·dl around a closed loop equals:", options: ["ε₀ × flux", "µ₀ × (total current enclosed)", "µ₀ε₀ × (flux change)", "Zero always"], ans: 1, exp: "Ampere's law: ∮B·dl = µ₀I_enclosed. For a long straight wire: B × 2πr = µ₀I → B = µ₀I/2πr. Modified Ampere-Maxwell law includes displacement current: ∮B·dl = µ₀(I_c + ε₀ dΦE/dt). NCERT Class 12, Ch 4 and Ch 8.", stars: 4 },
];

