const exam2Questions = [
  // BIOLOGY (Q1-Q40)
  { id: 1, subject: "Biology", section: "Genetics", q: "In the human genome, the number of base pairs is approximately:", options: ["3.2 million","32 million","3.2 billion","32 billion"], ans: 2, exp: "Human Genome Project (HGP): ~3.2 billion base pairs (3.2 × 10⁹ bp) in the haploid human genome. ~20,000–25,000 protein-coding genes (only ~1.5% of genome is coding). 99.9% of human DNA sequence is identical across individuals. NCERT Class 12, Ch 6.", stars: 5 },
  { id: 2, subject: "Biology", section: "Genetics", q: "Which enzyme synthesises the RNA primer during DNA replication in prokaryotes?", options: ["DNA polymerase I","DNA polymerase III","Primase (RNA polymerase)","Helicase"], ans: 2, exp: "DNA replication steps: Helicase unwinds the double helix → SSB proteins stabilise → Primase (a special RNA polymerase) synthesises a short RNA primer (5–10 nucleotides) → DNA Pol III extends in 5'→3' direction → DNA Pol I removes primers and replaces with DNA → Ligase seals nicks. NCERT Class 12, Ch 6.", stars: 5 },
  { id: 3, subject: "Biology", section: "Biotechnology", q: "The process of RNA interference (RNAi) is used in biotechnology to:", options: ["Amplify specific genes","Silence specific genes by using dsRNA complementary to target mRNA","Produce monoclonal antibodies","Insert foreign DNA into host cell"], ans: 1, exp: "RNAi (RNA interference): double-stranded RNA (dsRNA) triggers degradation of complementary mRNA → gene silencing. Discovered by Fire & Mello (Nobel 2006). Used in nematode pest control (tobacco plants protected from nematodes), potential gene therapy. NCERT Class 12, Ch 12.", stars: 5 },
  { id: 4, subject: "Biology", section: "Biotechnology", q: "Restriction endonucleases that cut DNA to produce 'blunt ends' are called:", options: ["EcoRI-type enzymes","Blunt-end cutters (e.g., SmaI, HaeIII)","Palindromic cutters","Exonucleases"], ans: 1, exp: "Restriction enzymes: (1) Sticky-end cutters — cut at palindromic sequences, leaving 5' or 3' overhangs (e.g., EcoRI: 5'…G↓AATTC…3'). (2) Blunt-end cutters — cut at the centre of palindrome leaving no overhangs (e.g., SmaI: CCC↓GGG). Sticky ends are used in rDNA technology. NCERT Class 12, Ch 11.", stars: 4 },
  { id: 5, subject: "Biology", section: "Biotechnology", q: "In gel electrophoresis of DNA, smaller fragments migrate:", options: ["Slower, away from negative electrode","Faster, towards positive electrode (anode)","At the same rate regardless of size","Towards negative electrode"], ans: 1, exp: "Gel electrophoresis: DNA is negatively charged (phosphate backbone) → migrates toward positive electrode (anode). Agarose gel acts as molecular sieve: smaller fragments move faster (less resistance). Fragments separated by size, visualised under UV with ethidium bromide staining. NCERT Class 12, Ch 11.", stars: 5 },
  { id: 6, subject: "Biology", section: "Genetics", q: "The 'Central Dogma' of molecular biology (as extended by Temin and Baltimore) includes:", options: ["DNA→RNA→Protein only","DNA→RNA→Protein AND RNA→DNA (reverse transcription)","RNA→DNA→Protein","Protein→RNA→DNA"], ans: 1, exp: "Classical Central Dogma (Francis Crick, 1958): DNA → RNA → Protein. Extended by Temin & Baltimore (1970 — Nobel 1975): RNA → DNA via reverse transcriptase in retroviruses (HIV, HTLV). Also: RNA → RNA (in RNA viruses). DNA → Protein (direct) is NOT observed. NCERT Class 12, Ch 6.", stars: 5 },
  { id: 7, subject: "Biology", section: "Biotechnology", q: "Cry proteins produced by Bacillus thuringiensis are toxic to insects because they:", options: ["Inhibit enzyme activity in insects","Form pores in the midgut epithelium, causing cell lysis and death","Block nerve impulse","Prevent moulting"], ans: 1, exp: "Bt toxin (Cry protein): encoded by cry genes; exists as protoxin in Bt. When insect ingests it → alkaline gut solubilises protoxin → trypsin-like enzymes activate it → activated Cry protein binds to midgut epithelial receptors → pores form → cell lysis → insect death. Harmless to humans (acidic gut). NCERT Class 12, Ch 12.", stars: 5 },
  { id: 8, subject: "Biology", section: "Biotechnology", q: "The 'molecular pharming' concept involves:", options: ["Farming of bacteria for pharmaceutical drugs","Using transgenic animals/plants to produce human therapeutic proteins in their milk/seeds","Producing vaccines by PCR","Gene therapy using viral vectors"], ans: 1, exp: "Molecular pharming: transgenic animals used as bioreactors to produce human proteins. Examples: Rosie (transgenic cow with human alpha-lactalbumin in milk for infant nutrition), transgenic goats producing human antithrombin III in milk. Also: transgenic plants producing edible vaccines. NCERT Class 12, Ch 12.", stars: 4 },
  { id: 9, subject: "Biology", section: "Genetics", q: "In co-dominance (ABO blood group), both alleles IA and IB are expressed in genotype IAIB because:", options: ["One allele suppresses the other","Both alleles are expressed simultaneously, producing both A and B antigens (type AB)","One allele is dominant over the other","They are sex-linked"], ans: 1, exp: "Co-dominance: both alleles expressed equally in heterozygote. IAIB → both A antigens and B antigens → Blood group AB. Contrast with incomplete dominance (intermediate phenotype). ABO is an example of both multiple allelism (3 alleles: IA, IB, i) and co-dominance (IA and IB). NCERT Class 12, Ch 5.", stars: 5 },
  { id: 10, subject: "Biology", section: "Genetics", q: "If a woman is carrier of haemophilia (XHXh) and her husband is normal (XHY), what fraction of their sons will be affected?", options: ["All sons","Half the sons (1/2)","No sons","One-quarter of sons"], ans: 1, exp: "Cross: XHXh (carrier female) × XHY (normal male). Sons: XHY (normal) and XhY (affected haemophiliac) — 1:1 ratio. ∴ 1/2 sons affected. Daughters: XHXH (normal) and XHXh (carrier) — none affected but half are carriers. X-linked recessive: affected males >> females. NCERT Class 12, Ch 5.", stars: 5 },
  { id: 11, subject: "Biology", section: "Biotechnology", q: "The process by which a bacterium takes up foreign DNA from its environment is called:", options: ["Transduction","Transformation","Conjugation","Transposition"], ans: 1, exp: "Mechanisms of gene transfer in bacteria: (1) Transformation — uptake of naked DNA from environment (Griffith's experiment, 1928); (2) Transduction — transfer via bacteriophage; (3) Conjugation — direct cell-to-cell contact via sex pilus (F factor). Competent bacteria can take up DNA. NCERT Class 12, Ch 11.", stars: 5 },
  { id: 12, subject: "Biology", section: "Health", q: "ELISA (Enzyme-Linked Immunosorbent Assay) is based on the principle of:", options: ["DNA hybridisation","Antigen–antibody interaction using enzyme-labeled antibodies","PCR amplification","Gel electrophoresis"], ans: 1, exp: "ELISA principle: Primary antibody binds antigen → secondary antibody (enzyme-conjugated) binds primary → enzyme converts colourless substrate to coloured product → quantification by spectrophotometer. Used for: HIV diagnosis, pregnancy test (hCG), detecting allergens, hepatitis B. NCERT Class 12, Ch 8.", stars: 5 },
  { id: 13, subject: "Biology", section: "Biotechnology", q: "Which is the cloning vector most commonly used in plant genetic engineering?", options: ["pBR322","Ti plasmid of Agrobacterium tumefaciens","Lambda phage","Cosmid"], ans: 1, exp: "Ti (tumour-inducing) plasmid: natural vector in Agrobacterium tumefaciens. T-DNA (transferred DNA) integrates into plant nuclear genome. 'Disarmed' Ti plasmid (oncogenes removed) used for plant transformation. Alternative: biolistic (gene gun) — gold/tungsten particles coated with DNA fired into plant cells. NCERT Class 12, Ch 11.", stars: 5 },
  { id: 14, subject: "Biology", section: "Genetics", q: "The term 'genomics' refers to:", options: ["Study of a single gene","Study of entire genome including sequencing, mapping, and functional analysis","Study of only coding sequences","Production of genetically modified organisms"], ans: 1, exp: "Genomics: comprehensive study of genomes. Structural genomics: sequencing, mapping. Functional genomics: gene expression and function. Comparative genomics: comparing genomes across species. Proteomics: study of all proteins. Bioinformatics: computational analysis of biological data. NCERT Class 12, Ch 6.", stars: 4 },
  { id: 15, subject: "Biology", section: "Ecology", q: "The competitive exclusion principle was given by:", options: ["Darwin","Lotka & Volterra","G.F. Gause","Malthus"], ans: 2, exp: "Gause's competitive exclusion principle (1934): Two species competing for exactly the same resources (same ecological niche) cannot coexist stably — one will eventually eliminate the other. Resource partitioning allows coexistence through niche differentiation. NCERT Class 12, Ch 13.", stars: 5 },
  { id: 16, subject: "Biology", section: "Ecology", q: "Primary productivity in an ecosystem refers to:", options: ["Total biomass of all living organisms","Rate of production of organic matter by producers per unit area per unit time","Total energy released by decomposers","Rate of consumption by herbivores"], ans: 1, exp: "Productivity types: Gross Primary Productivity (GPP) = total rate of photosynthesis. Net Primary Productivity (NPP) = GPP − Respiration. Secondary Productivity = rate of biomass production by consumers. Units: g/m²/year or kcal/m²/year. Tropical rainforests have highest NPP; deserts and deep oceans have lowest. NCERT Class 12, Ch 14.", stars: 5 },
  { id: 17, subject: "Biology", section: "Ecology", q: "The concept of 'ecological succession' states that:", options: ["Ecosystems never change over time","Communities change over time in a directional sequence until a stable climax community is reached","Only physical factors determine species composition","Species diversity decreases with succession"], ans: 1, exp: "Ecological succession: Primary succession (bare substrate, e.g., bare rock, new lava) — pioneer species → climax. Secondary succession (existing soil, e.g., after forest fire, abandoned farmland) — faster, as soil already developed. Hydrarch succession: water → terrestrial. Xerarch: dry rock → forest. NCERT Class 12, Ch 14.", stars: 5 },
  { id: 18, subject: "Biology", section: "Evolution", q: "In natural selection, which term describes individuals that survive and reproduce successfully?", options: ["Survival of the fittest (differential reproductive success)","Genetic drift","Gene flow","Mutation"], ans: 0, exp: "Natural selection (Darwin): individuals with favourable traits survive and reproduce more → heritable traits become more common in population over generations. 'Fitness' = reproductive success, not physical strength. Three types: Directional, Stabilising, Disruptive selection. NCERT Class 12, Ch 7.", stars: 5 },
  { id: 19, subject: "Biology", section: "Ecology", q: "Eutrophication of water bodies is caused by:", options: ["Increased CO₂","Excess nutrients (nitrogen and phosphorus) causing algal blooms → oxygen depletion","Heavy metal pollution","Decreased salinity"], ans: 1, exp: "Cultural eutrophication: run-off of agricultural fertilisers (N, P) → excessive algal growth → algae die → bacterial decomposition consumes O₂ → hypoxic conditions → fish kill. BOD (Biochemical Oxygen Demand) increases. Clean water: BOD < 1 ppm; polluted: > 5 ppm. NCERT Class 12, Ch 16.", stars: 5 },
  { id: 20, subject: "Biology", section: "Ecology", q: "Which of the following is a decomposer organism in an ecosystem?", options: ["Grasshopper","Fungi (e.g., Rhizopus, Penicillium, Agaricus)","Earthworm (detritivore)","Hawk"], ans: 1, exp: "Decomposers (saprotrophic organisms): fungi and bacteria that break down dead organic matter → release inorganic nutrients (mineralization). Detritivores (e.g., earthworm, millipede) mechanically break down detritus → enhance decomposer activity. Together they complete nutrient cycling. NCERT Class 12, Ch 14.", stars: 5 },
  { id: 21, subject: "Biology", section: "Evolution", q: "The most widely accepted theory for origin of life on Earth is:", options: ["Panspermia hypothesis","Chemical theory (Oparin-Haldane hypothesis — life arose from complex chemistry)","Special creation","Spontaneous generation"], ans: 1, exp: "Oparin (1924) and Haldane (1929): life originated from chemical reactions in early Earth's reducing atmosphere (CH₄, NH₃, H₂, H₂O). Supported by Miller-Urey experiment (1953). RNA world hypothesis: RNA was first genetic material (can both store info and catalyse reactions). NCERT Class 12, Ch 7.", stars: 5 },
  { id: 22, subject: "Biology", section: "Evolution", q: "The phenomenon of 'genetic drift' is most significant in:", options: ["Large populations","Small populations where random changes in allele frequency can be large","Populations with balanced polymorphism","Populations under strong natural selection"], ans: 1, exp: "Genetic drift (Sewall Wright effect): random changes in allele frequencies due to chance events — most significant in small populations. Bottleneck effect (population crash → reduced diversity) and Founder effect (small group colonises new area). Can lead to loss of alleles by chance alone — NOT adaptive. NCERT Class 12, Ch 7.", stars: 5 },
  { id: 23, subject: "Biology", section: "Ecology", q: "Ex situ conservation of biodiversity involves:", options: ["Protection in the natural habitat (national parks, sanctuaries)","Conservation outside the natural habitat (seed banks, zoos, botanical gardens, cryopreservation)","Creation of new habitats","Eliminating invasive species only"], ans: 1, exp: "Ex situ: Seed banks (National Bureau of Plant Genetic Resources, New Delhi), botanical gardens (Kew Gardens), zoological parks, tissue culture, cryopreservation (−196°C liquid N₂). In situ: biosphere reserves, national parks, wildlife sanctuaries, sacred groves. NCERT Class 12, Ch 15.", stars: 5 },
  { id: 24, subject: "Biology", section: "Ecology", q: "The 'rivet popper hypothesis' of biodiversity is associated with:", options: ["Ehrlich and Ehrlich — each species is like a rivet; loss of any weakens the ecosystem","Malthus","Wilson","Hutchinson"], ans: 0, exp: "Paul and Anne Ehrlich's rivet popper hypothesis: each species in an ecosystem = rivet in an aeroplane. A few rivets can be removed without immediate disaster, but beyond a threshold, the plane (ecosystem) crashes. Emphasises interconnectedness and unpredictability of species loss. NCERT Class 12, Ch 15.", stars: 4 },
  { id: 25, subject: "Biology", section: "Ecology", q: "The relationship between mycorrhizae (fungi) and plant roots is an example of:", options: ["Parasitism","Commensalism","Mutualism","Amensalism"], ans: 2, exp: "Mycorrhizae: symbiotic association between fungi and plant roots. Fungus gets carbohydrates from plant; plant gets enhanced mineral absorption (especially phosphorus) and drought resistance from fungus. Both benefit (+/+) = mutualism. 90% of land plants have mycorrhizal associations. NCERT Class 12, Ch 13.", stars: 5 },
  { id: 26, subject: "Biology", section: "Ecology", q: "Biomagnification of DDT (and other persistent organochlorines) refers to:", options: ["Degradation of DDT in soil","Increase in concentration of DDT at each successive trophic level in a food chain","Decrease in DDT concentration with distance from source","Absorption of DDT by soil"], ans: 1, exp: "Biomagnification (biological magnification): DDT is fat-soluble, not metabolised or excreted easily. Concentration multiplies up the food chain: phytoplankton < zooplankton < small fish < large fish < fish-eating birds (osprey, eagles). Causes thin eggshells → reproductive failure. NCERT Class 12, Ch 16.", stars: 5 },
  { id: 27, subject: "Biology", section: "Physiology", q: "The oxygen dissociation curve (ODC) of haemoglobin is sigmoid (S-shaped) because:", options: ["Haemoglobin has only one binding site","Cooperative binding — O₂ binding to one subunit increases affinity of remaining subunits","CO₂ helps in O₂ binding","The curve is determined by temperature alone"], ans: 1, exp: "Haemoglobin (Hb): 4 subunits (2α + 2β), each with one haem group (Fe²⁺). Cooperative binding: first O₂ binds → conformational change → easier binding of subsequent O₂ → sigmoid curve. Bohr effect: increased CO₂/H⁺/temperature shifts curve right → more O₂ released at tissues. NCERT Class 11, Ch 17.", stars: 5 },
  { id: 28, subject: "Biology", section: "Physiology", q: "Surfactant in the lungs is produced by which type of cells, and its function is to:", options: ["Type I pneumocytes; gas exchange","Type II pneumocytes; reduce surface tension in alveoli, preventing collapse","Macrophages; phagocytosis","Goblet cells; mucus secretion"], ans: 1, exp: "Pulmonary surfactant: dipalmitoyl phosphatidylcholine (DPPC) produced by Type II pneumocytes. Reduces surface tension of alveolar fluid → prevents alveolar collapse during expiration. Deficiency in premature infants → Respiratory Distress Syndrome (RDS/hyaline membrane disease). NCERT Class 11, Ch 17.", stars: 5 },
  { id: 29, subject: "Biology", section: "Physiology", q: "Antidiuretic hormone (ADH/vasopressin) acts on which part of the nephron to increase water reabsorption?", options: ["Proximal Convoluted Tubule (PCT)","Collecting Duct and Distal Convoluted Tubule (DCT)","Loop of Henle (ascending limb)","Glomerulus"], ans: 1, exp: "ADH increases permeability of DCT and collecting duct to water by inserting aquaporin channels (AQP2) into tubular cells → more water reabsorbed → concentrated urine. Secreted by posterior pituitary. Trigger: increased plasma osmolarity / decreased blood volume. Alcohol inhibits ADH → diuresis. NCERT Class 11, Ch 19.", stars: 5 },
  { id: 30, subject: "Biology", section: "Physiology", q: "Juxtaglomerular apparatus (JGA) in the kidney responds to low blood pressure by secreting:", options: ["Aldosterone directly","Renin, which initiates the Renin-Angiotensin-Aldosterone System (RAAS)","ADH","Erythropoietin"], ans: 1, exp: "RAAS: Low blood pressure/low Na⁺ → JGA cells secrete renin → Renin converts angiotensinogen to Angiotensin I → ACE converts to Angiotensin II → stimulates adrenal cortex to secrete aldosterone → Na⁺ and water reabsorption in DCT/CD → increased blood volume and pressure. NCERT Class 11, Ch 19.", stars: 5 },
  { id: 31, subject: "Biology", section: "Physiology", q: "If the SA node is damaged, the heart beats at approximately what rate driven by the AV node?", options: ["72 beats/min","40–60 beats/min","100 beats/min","20 beats/min"], ans: 1, exp: "SA node (right atrium): intrinsic rate 70–75 beats/min — sets the pace. AV node (atrioventricular): intrinsic rate 40–55 beats/min. Bundle of His: 30–40 beats/min. Purkinje fibres: 20–30 beats/min. If SA node fails → AV node takes over → slower heart rate (idioventricular rhythm). NCERT Class 11, Ch 18.", stars: 5 },
  { id: 32, subject: "Biology", section: "Reproduction", q: "Which contraceptive method has the highest failure rate?", options: ["IUD (Copper-T)","Oral contraceptive pills","Condom (barrier method)","Lactational amenorrhoea"], ans: 3, exp: "Failure rates: OCP ~0.1–1%, Copper-T ~0.6–0.8%, Condom ~2–15% (typical use), Lactational amenorrhoea (breastfeeding suppresses ovulation) ~2–5% but very unreliable after 6 months or if baby supplemented. Vasectomy/tubectomy have lowest failure rates (<0.1%). NCERT Class 12, Ch 4.", stars: 5 },
  { id: 33, subject: "Biology", section: "Reproduction", q: "The 'Amniocentesis' technique is used for:", options: ["Treatment of infertility","Prenatal detection of chromosomal abnormalities (Down's, sex determination)","Artificial insemination","Treatment of ectopic pregnancy"], ans: 1, exp: "Amniocentesis: withdrawal of amniotic fluid (contains foetal cells) at 14–18 weeks. Foetal cells cultured → karyotyping → detects Down's (Trisomy 21), Turner's, Klinefelter's, other chromosomal defects, and metabolic disorders. NOTE: banned for sex determination in India (PCPNDT Act, 1994). NCERT Class 12, Ch 4.", stars: 5 },
  { id: 34, subject: "Biology", section: "Reproduction", q: "In the menstrual cycle, progesterone levels are HIGHEST during which phase?", options: ["Menstrual phase (days 1–5)","Follicular/proliferative phase (days 6–13)","Luteal/secretory phase (days 15–28)","During menopause"], ans: 2, exp: "Luteal phase: after ovulation (day 14), corpus luteum secretes PROGESTERONE (mainly) and oestrogen → endometrium thickens and becomes secretory. If no fertilisation: corpus luteum degenerates → progesterone drops → menstruation begins. If fertilisation: HCG maintains corpus luteum. NCERT Class 12, Ch 3.", stars: 5 },
  { id: 35, subject: "Biology", section: "Health", q: "The disease 'Typhoid' is caused by which pathogen?", options: ["Salmonella typhi; rose-coloured spots on abdomen, Widal test positive","Vibrio cholerae; rice-water diarrhoea","Plasmodium vivax; recurrent fever every 48 hours","Clostridium tetani; muscle spasms"], ans: 0, exp: "Typhoid fever (Salmonella typhi): transmitted via contaminated food/water (faecal-oral route). Symptoms: sustained high fever, headache, weakness, rose-coloured spots on abdomen, constipation/diarrhoea. Diagnosis: Widal test (agglutination). Charles-Darwin suspected typhoid. NCERT Class 12, Ch 8.", stars: 5 },
  { id: 36, subject: "Biology", section: "Health", q: "Interferons are proteins secreted by virus-infected cells. Their function is to:", options: ["Directly kill the virus","Warn uninfected neighbouring cells to produce antiviral proteins and resist viral infection","Produce antibodies","Activate T-cells only"], ans: 1, exp: "Interferons (IFN-α, IFN-β, IFN-γ): glycoproteins secreted by virus-infected cells. They diffuse to neighbouring uninfected cells → activate genes encoding antiviral proteins → block viral replication. Species-specific but not virus-specific. Non-specific defence (innate immunity). NCERT Class 12, Ch 8.", stars: 5 },
  { id: 37, subject: "Biology", section: "Physiology", q: "The primary energy source for muscle contraction immediately at the start of exercise is:", options: ["Blood glucose","Creatine phosphate (phosphocreatine) → rapidly regenerates ATP","Fat oxidation","Protein breakdown"], ans: 1, exp: "Energy sources in muscle contraction sequence: (1) Available ATP (immediate, 2–3 seconds), (2) Creatine phosphate (next ~10 seconds), (3) Glycolysis (up to 2 min, anaerobic), (4) Aerobic oxidation of glucose and fats (prolonged). Phosphocreatine + ADP → Creatine + ATP (creatine kinase). NCERT Class 11, Ch 20.", stars: 5 },
  { id: 38, subject: "Biology", section: "Physiology", q: "Which part of the brain is responsible for maintaining balance and coordinating voluntary muscular movements?", options: ["Cerebrum","Cerebellum","Medulla oblongata","Hypothalamus"], ans: 1, exp: "Cerebellum (hindbrain): balance, posture, coordination of voluntary movements. Damage → ataxia (loss of coordination). Medulla oblongata: controls breathing, heart rate, vomiting. Hypothalamus: thermoregulation, hunger, sleep, pituitary hormone control. Cerebrum: thinking, reasoning, voluntary movement. NCERT Class 11, Ch 21.", stars: 5 },
  { id: 39, subject: "Biology", section: "Physiology", q: "The hormone calcitonin is produced by the thyroid gland. Its function is to:", options: ["Increase blood calcium levels","Decrease blood calcium levels by promoting bone calcium deposition","Stimulate T3/T4 production","Regulate blood glucose"], ans: 1, exp: "Calcitonin (thyroid C-cells): secreted when blood Ca²⁺ is HIGH → promotes calcium deposition in bones → decreases blood calcium. Antagonist: Parathyroid hormone (PTH) → mobilises calcium from bones → increases blood calcium. Vitamin D → increases intestinal Ca absorption. NCERT Class 11, Ch 22.", stars: 5 },
  { id: 40, subject: "Biology", section: "Genetics", q: "In the lac operon, the operator sequence is located between:", options: ["Promoter and the structural genes (lacZ, lacY, lacA)","Structural genes and terminator","Promoter and regulator gene","Before the promoter"], ans: 0, exp: "Lac operon organisation (5'→3'): Regulator gene (lacI) → Promoter (P) → Operator (O) → Structural genes (lacZ — β-galactosidase, lacY — permease, lacA — transacetylase) → Terminator. Repressor (from lacI) binds operator → blocks RNA polymerase. Inducer (allolactose) removes repressor. NCERT Class 12, Ch 6.", stars: 5 },
  // CHEMISTRY (Q41-Q70)
  { id: 41, subject: "Chemistry", section: "Organic", q: "Which of the following undergoes aldol condensation?", options: ["Benzaldehyde (no α-H)","Formaldehyde (no α-H)","Acetaldehyde (has α-H)","Chloral (CCl₃CHO)"], ans: 2, exp: "Aldol condensation: aldehydes/ketones with at least one α-H react with dilute NaOH → aldol (β-hydroxy carbonyl compound) → on heating → α,β-unsaturated carbonyl compound. Acetaldehyde (CH₃CHO): α-H present → aldol condensation possible. Benzaldehyde, HCHO, CCl₃CHO — no α-H → cannot form enolate. NCERT Class 12, Ch 12.", stars: 5 },
  { id: 42, subject: "Chemistry", section: "Organic", q: "Which of the following correctly describes the Gabriel synthesis?", options: ["Synthesis of aldehydes from Grignard reagents","Synthesis of primary amines (R-NH₂) from phthalimide via alkylation and hydrolysis","Synthesis of carboxylic acids from nitriles","Synthesis of phenol from benzene sulphonate"], ans: 1, exp: "Gabriel synthesis: Phthalimide + KOH → potassium phthalimide → + alkyl halide (R-X) → N-alkylphthalimide → hydrolysis with NaOH/H₂O → primary amine (R-NH₂) + phthalic acid. Advantage: gives pure primary amines (no secondary/tertiary contamination). NCERT Class 12, Ch 13.", stars: 5 },
  { id: 43, subject: "Chemistry", section: "Organic", q: "The reaction of an alcohol with acetic anhydride in the presence of pyridine gives:", options: ["Ether","Ester (acetate)","Aldehyde","Acyl chloride"], ans: 1, exp: "Esterification with acetic anhydride: R-OH + (CH₃CO)₂O → R-OCOCH₃ (ester) + CH₃COOH. Pyridine acts as a catalyst (absorbs HCl/acid formed). This is a mild, efficient esterification method. Fischer esterification (H⁺ catalyst) is reversible; acetic anhydride method is irreversible. NCERT Class 12, Ch 11.", stars: 5 },
  { id: 44, subject: "Chemistry", section: "Organic", q: "Which test is used to identify a primary alcohol?", options: ["Tollens' test","Lucas test — primary alcohols react slowly (or not at room temperature) with Lucas reagent","Fehling's test","Iodoform test"], ans: 1, exp: "Lucas test (ZnCl₂ + conc. HCl): used to distinguish 1°, 2°, 3° alcohols. 3° alcohol → immediate turbidity (SN1, stable 3° carbocation). 2° alcohol → turbidity in 5 min. 1° alcohol → no turbidity at room temperature (must be heated). Applicable to alcohols with ≤6 carbon atoms (water-soluble). NCERT Class 12, Ch 11.", stars: 5 },
  { id: 45, subject: "Chemistry", section: "Organic", q: "Which of the following is NOT true about benzene?", options: ["It undergoes electrophilic aromatic substitution","It has 6 equivalent C-C bonds of intermediate length (1.40 Å)","It undergoes nucleophilic substitution readily","It resists addition reactions despite 3 double bonds"], ans: 2, exp: "Benzene properties: (1) Aromatic (4n+2 π electrons, n=1 → 6π electrons, Hückel's rule); (2) Undergoes EAS (electrophilic aromatic substitution); (3) Resists addition (C-C bond length 1.40Å); (4) Does NOT undergo nucleophilic substitution readily. NCERT Class 11, Ch 13.", stars: 5 },
  { id: 46, subject: "Chemistry", section: "Organic", q: "The IUPAC name of the compound (CH₃)₃C-NH₂ is:", options: ["tert-butylamine","2-methylpropan-2-amine","Propylamine","N,N-dimethylethylamine"], ans: 1, exp: "(CH₃)₃C-NH₂: parent = 2-methylpropan-2-amine (4C branched chain). It is a tertiary amine by structure but a primary amine by IUPAC classification (NH₂ directly attached to carbon). IUPAC naming of amines: alkan-1-amine (primary), N-alkylamines (secondary/tertiary). NCERT Class 12, Ch 13.", stars: 5 },
  { id: 47, subject: "Chemistry", section: "Organic", q: "Hofmann rearrangement converts a primary amide to:", options: ["Secondary amine","Primary amine with one less carbon (R-CO-NH₂ → R-NH₂)","Nitrile","Tertiary amine"], ans: 1, exp: "Hofmann rearrangement: RCONH₂ + Br₂ + 4NaOH → RNH₂ + Na₂CO₃ + 2NaBr + 2H₂O. The carbon chain length decreases by 1 (carboxyl group lost as CO₂²⁻). The nitrogen migrates. This is a key method to prepare primary amines with one fewer carbon. NCERT Class 12, Ch 13.", stars: 5 },
  { id: 48, subject: "Chemistry", section: "Organic", q: "The addition of HBr to but-1-ene following Markovnikov's rule gives:", options: ["1-bromobutane","2-bromobutane","3-bromobutane","4-bromobutane"], ans: 1, exp: "Markovnikov's rule: H adds to carbon with more H atoms (less substituted), Br adds to more substituted carbon. CH₂=CH-CH₂CH₃ + HBr → CH₃-CHBr-CH₂CH₃ (2-bromobutane). Mechanism: H⁺ adds to C1 → more stable 2° carbocation at C2 → Br⁻ attacks C2. NCERT Class 11, Ch 13.", stars: 5 },
  { id: 49, subject: "Chemistry", section: "Organic", q: "Which of the following correctly represents saponification?", options: ["Hydrolysis of fats/oils with NaOH → glycerol + soap (sodium salt of fatty acid)","Esterification of fatty acids","Hydrogenation of unsaturated fats","Rancidity of fats"], ans: 0, exp: "Saponification: triglyceride (fat/oil) + NaOH → glycerol + 3 sodium salts of fatty acids (soap). Soap action: hydrophilic end (-COO⁻Na⁺) dissolves in water; hydrophobic hydrocarbon chain dissolves grease → micelle formation surrounds grease → washed away. Soft soap uses KOH. NCERT Class 12, Ch 16.", stars: 5 },
  { id: 50, subject: "Chemistry", section: "Organic", q: "The term 'denaturation' of proteins refers to:", options: ["Breaking of peptide bonds","Disruption of secondary and tertiary structure (H-bonds, disulphide bonds, hydrophobic interactions) WITHOUT breaking peptide bonds","Synthesis of new proteins","Hydrolysis into amino acids"], ans: 1, exp: "Denaturation: caused by heat, pH change, heavy metals, organic solvents, urea → protein loses 3D structure and biological activity. Primary structure (peptide bonds) is NOT broken. Examples: boiling egg (albumin), blood clotting. Renaturation (refolding) possible under mild conditions. NCERT Class 12, Ch 14.", stars: 5 },
  { id: 51, subject: "Chemistry", section: "Organic", q: "Which reducing sugar is NOT formed by hydrolysis of sucrose?", options: ["Glucose","Fructose","Galactose","Both glucose and fructose"], ans: 2, exp: "Sucrose = glucose + fructose (α-1,β-2 glycosidic bond). Hydrolysis (invertase enzyme or acid): sucrose → glucose + fructose. Product = 'invert sugar'. Galactose is NOT a product of sucrose hydrolysis. Galactose is produced from lactose hydrolysis (lactose → glucose + galactose). NCERT Class 12, Ch 14.", stars: 5 },
  { id: 52, subject: "Chemistry", section: "Organic", q: "Which of the following statements about nucleic acids is CORRECT?", options: ["DNA has uracil, RNA has thymine","In DNA, adenine pairs with thymine (2 H-bonds); guanine pairs with cytosine (3 H-bonds)","RNA has deoxyribose sugar","DNA is single-stranded"], ans: 1, exp: "Watson-Crick DNA: A=T (2 hydrogen bonds, weaker), G≡C (3 hydrogen bonds, stronger). High GC content → higher melting temperature. DNA: deoxyribose + A, T, G, C. RNA: ribose + A, U, G, C (uracil replaces thymine). Chargaff's rules: A=T, G=C in double-stranded DNA. NCERT Class 12, Ch 14.", stars: 5 },
  { id: 53, subject: "Chemistry", section: "Organic", q: "Which drugs act as tranquilizers (anti-anxiety agents)?", options: ["Morphine and heroin (narcotics)","Barbiturates, benzodiazepines (e.g., diazepam/Valium)","Amphetamines (stimulants)","Aspirin and ibuprofen (NSAIDs)"], ans: 1, exp: "Tranquilizers: depress CNS activity, reduce anxiety. Barbiturates (phenobarbitone, seconal) — hypnotic sedatives. Benzodiazepines (diazepam, chlordiazepoxide) — mild tranquilizers. Morphine/heroin are narcotics (analgesics + sedatives). Amphetamines are stimulants. NCERT Class 12, Ch 16.", stars: 5 },
  { id: 54, subject: "Chemistry", section: "Organic", q: "Nylon-6 is prepared from which monomer?", options: ["Hexamethylenediamine + adipic acid","Caprolactam (ring-opening polymerisation)","Ethylene glycol + terephthalic acid","Styrene"], ans: 1, exp: "Nylon-6: ring-opening polymerisation of caprolactam (a cyclic amide/lactam). [-NH-(CH₂)₅-CO-]n. Different from Nylon-6,6 (condensation polymer of hexamethylenediamine + adipic acid). Both are polyamides (peptide-like bonds). Used in ropes, tyre cords, fabrics. NCERT Class 12, Ch 15.", stars: 5 },
  { id: 55, subject: "Chemistry", section: "Organic", q: "Baeyer's reagent (cold dilute alkaline KMnO₄) is used to test for:", options: ["Aromaticity","Presence of C=C double bond (converts alkene to diol, solution decolorises)","Carboxylic acids","Halide detection"], ans: 1, exp: "Baeyer's test: cold, dilute, alkaline KMnO₄ (purple/pink) + alkene → diol (vicinal diol) + colourless MnO₂ (brown ppt). Decolourisation indicates unsaturation (C=C or C≡C). Positive for alkenes, alkynes, aldehydes. Negative for alkanes and benzene. NCERT Class 11, Ch 13.", stars: 5 },
  { id: 56, subject: "Chemistry", section: "Physical", q: "The lattice enthalpy of an ionic compound (Born-Haber cycle) is defined as:", options: ["Energy released when 1 mol ionic compound dissolves in water","Energy released when gaseous ions combine to form 1 mol of ionic crystal","Enthalpy of formation","Heat of vaporisation of the compound"], ans: 1, exp: "Born-Haber cycle: uses Hess's law to calculate lattice enthalpy indirectly. Lattice enthalpy of NaCl = Na⁺(g) + Cl⁻(g) → NaCl(s), ΔH = −788 kJ/mol. High lattice energy → more stable ionic compound → higher melting point. NCERT Class 11, Ch 4+6.", stars: 5 },
  { id: 57, subject: "Chemistry", section: "Inorganic", q: "The correct order of ionic radius for isoelectronic species N³⁻, O²⁻, F⁻, Na⁺, Mg²⁺ is:", options: ["N³⁻ > O²⁻ > F⁻ > Na⁺ > Mg²⁺","Mg²⁺ > Na⁺ > F⁻ > O²⁻ > N³⁻","F⁻ > O²⁻ > N³⁻ > Na⁺ > Mg²⁺","All are equal as isoelectronic"], ans: 0, exp: "Isoelectronic species (all have 10 electrons): but nuclear charge increases N(7) < O(8) < F(9) < Na(11) < Mg(12). Higher nuclear charge → more attraction → smaller radius. ∴ N³⁻ (10e⁻, 7p⁺) largest → Mg²⁺ (10e⁻, 12p⁺) smallest. NCERT Class 11, Ch 3.", stars: 5 },
  { id: 58, subject: "Chemistry", section: "Inorganic", q: "According to Fajans' rules, covalent character is MORE when the cation:", options: ["Is large and has low charge","Is small, highly charged, and has 18-electron configuration","Is Na⁺ or K⁺","Has noble gas configuration"], ans: 1, exp: "Fajans' rules: covalent character increases when cation is (1) small, (2) highly charged, (3) has 18-electron (pseudo-noble gas) configuration — polarises the anion more. Anion: large size and high charge increase polarisability. Examples: FeCl₃ (more ionic) vs FeCl₂ (more covalent due to higher charge). NCERT Class 11, Ch 4.", stars: 4 },
  { id: 59, subject: "Chemistry", section: "Inorganic", q: "Which of the following transition metal ions is colourless?", options: ["Mn²⁺ (5 d-electrons)","Fe²⁺ (6 d-electrons)","Sc³⁺ (0 d-electrons)","Cu²⁺ (9 d-electrons)"], ans: 2, exp: "Colour in transition metal ions: due to d-d transitions (absorption of visible light). Requires partially filled d-orbitals AND d-d electron transition possible. Sc³⁺ = [Ar] 3d⁰ — no d-electrons → no d-d transitions → colourless. Similarly Ti⁴⁺ (d⁰), Zn²⁺ (d¹⁰, fully filled) are colourless. NCERT Class 12, Ch 8.", stars: 5 },
  { id: 60, subject: "Chemistry", section: "Inorganic", q: "In the complex [Fe(CN)₆]⁴⁻, the oxidation state of Fe is:", options: ["+3","+2","+1","0"], ans: 1, exp: "[Fe(CN)₆]⁴⁻: overall charge = −4. CN⁻ = −1 each × 6 = −6. Let Fe = x. x + (−6) = −4 → x = +2. Fe²⁺ = ferrocyanide (hexacyanoferrate(II)). [Fe(CN)₆]³⁻ = ferricyanide (Fe³⁺). Prussian blue = Fe₄[Fe(CN)₆]₃ = Fe³⁺ + [Fe(CN)₆]⁴⁻. NCERT Class 12, Ch 9.", stars: 5 },
  { id: 61, subject: "Chemistry", section: "Physical", q: "Henry's law states that:", options: ["Vapour pressure of solution = mole fraction × vapour pressure of pure solvent","Amount of gas dissolved in a liquid is directly proportional to its partial pressure above the liquid","Osmotic pressure = MRT","Boiling point elevation is proportional to molality"], ans: 1, exp: "Henry's law: p = KH × x (p = partial pressure of gas, KH = Henry's constant, x = mole fraction in solution). Used to explain: (1) Fizzing of soda when bottle opened, (2) Blood nitrogen in deep sea divers (bends), (3) Decreased O₂ solubility at high altitudes. NCERT Class 12, Ch 2.", stars: 5 },
  { id: 62, subject: "Chemistry", section: "Physical", q: "Which of the following is paramagnetic?", options: ["N₂","O₂","F₂","Ne"], ans: 1, exp: "O₂ paramagnetic: Molecular orbital theory: (σ1s)²(σ*1s)²(σ2s)²(σ*2s)²(σ2p)²(π2p)⁴(π*2p)² — 2 unpaired electrons in degenerate π* orbitals → paramagnetic. N₂: bond order 3, no unpaired electrons → diamagnetic. F₂: all paired, diamagnetic. NCERT Class 11, Ch 4.", stars: 5 },
  { id: 63, subject: "Chemistry", section: "Physical", q: "The electrode potential of the standard hydrogen electrode (SHE) is taken as:", options: ["−1.0 V","0.0 V","+1.0 V","−0.76 V"], ans: 1, exp: "Standard Hydrogen Electrode (SHE): H₂(g, 1 atm) | H⁺(1M). E° = 0.00 V by convention (reference electrode). All other standard electrode potentials are measured relative to SHE. Cu²⁺/Cu: +0.34 V. Zn²⁺/Zn: −0.76 V. More positive = stronger oxidising agent. NCERT Class 12, Ch 3.", stars: 5 },
  { id: 64, subject: "Chemistry", section: "Physical", q: "The rate constant 'k' of a reaction changes when:", options: ["Concentration of reactants changes","Temperature changes (Arrhenius equation: k = Ae^(−Ea/RT))","Pressure changes (for reactions in solution)","Volume of the reaction vessel changes"], ans: 1, exp: "Arrhenius equation: k = A × e^(−Ea/RT). k depends on: (1) Temperature (increases exponentially with T), (2) Activation energy (Ea), (3) Catalyst (lowers Ea → increases k). k does NOT depend on concentration, pressure (for solutions), or volume. NCERT Class 12, Ch 4.", stars: 5 },
  { id: 65, subject: "Chemistry", section: "Physical", q: "Buffer solution is defined as a solution that:", options: ["Has pH = 7.0","Resists changes in pH on addition of small amounts of acid or base","Contains only weak acid","Has very low ionic strength"], ans: 1, exp: "Buffer: weak acid + its conjugate base (acidic buffer, e.g., CH₃COOH/CH₃COONa) or weak base + conjugate acid (basic buffer, e.g., NH₃/NH₄Cl). Henderson-Hasselbalch: pH = pKa + log([A⁻]/[HA]). Buffer capacity is maximum when pH = pKa. NCERT Class 11, Ch 7.", stars: 5 },
  { id: 66, subject: "Chemistry", section: "Physical", q: "Adsorption of gases on solid surface is exothermic. Which statement is correct?", options: ["Adsorption decreases with increasing temperature","Adsorption increases with increasing temperature","Adsorption is unaffected by temperature","Adsorption follows Henry's law"], ans: 0, exp: "Physisorption (physical adsorption): weak van der Waals forces, low enthalpy (~20–40 kJ/mol), reversible, multi-layered, decreases with increasing T. Chemisorption (chemical adsorption): strong chemical bonds, high enthalpy (~80–240 kJ/mol), monolayer, may increase then decrease with T. NCERT Class 12, Ch 5.", stars: 5 },
  { id: 67, subject: "Chemistry", section: "Inorganic", q: "The Ellingham diagram is used to predict:", options: ["Feasibility of extraction of metals from their oxides (using carbon/CO as reductant)","Solubility of ionic compounds","Rate of electrochemical reactions","Boiling points of metals"], ans: 0, exp: "Ellingham diagram: plots ΔG° vs Temperature for metal oxide formation and C→CO/CO₂. If the metal oxide line is ABOVE the C→CO line → carbon can reduce the oxide (ΔG° negative for overall reaction). Used in: blast furnace (iron extraction), copper smelting. NCERT Class 12, Ch 6.", stars: 5 },
  { id: 68, subject: "Chemistry", section: "Inorganic", q: "Concrete is a mixture of:", options: ["Sand + gravel + water","Portland cement + sand + aggregate (gravel) + water","Calcium carbonate + silica","Slaked lime + sand"], ans: 1, exp: "Portland cement (Joseph Aspdin, 1824): made by calcining limestone + clay. Composition: Ca₂SiO₄, Ca₃SiO₅, Ca₃Al₂O₆, Ca₄Al₂Fe₂O₁₀. When water added → hydration reactions → gel → hardens (setting). Concrete: cement + sand + gravel + water. Reinforced concrete: steel rods embedded. NCERT Class 12, Ch 7.", stars: 5 },
  { id: 69, subject: "Chemistry", section: "Inorganic", q: "Which element shows the phenomenon of 'inert pair effect' in its lower oxidation state?", options: ["Carbon","Nitrogen","Lead (Pb) — prefers +2 over +4","Sulphur"], ans: 2, exp: "Inert pair effect: heavier elements in groups 13, 14, 15 prefer lower oxidation states due to reluctance of 6s² electrons to participate in bonding. Pb²⁺ more stable than Pb⁴⁺; Sn²⁺ less stable than Sn⁴⁺. Also: Tl⁺, Bi³⁺ preferred. The 6s electrons become inert. NCERT Class 12, Ch 7.", stars: 5 },
  { id: 70, subject: "Chemistry", section: "Physical", q: "Disproportionation reaction involves:", options: ["Two different elements undergoing oxidation and reduction","A single species undergoing simultaneous oxidation AND reduction (self-redox)","An element being oxidised only","Two substances reacting with no change in oxidation state"], ans: 1, exp: "Disproportionation: same species is oxidised and reduced simultaneously. Example: Cl₂ + 2NaOH → NaCl + NaOCl + H₂O (Cl₂ → Cl⁻ and Cl⁺). H₂O₂ → H₂O + O₂. Cu⁺ → Cu⁰ + Cu²⁺. Comproportionation is the reverse. NCERT Class 11, Ch 8.", stars: 5 },
  // PHYSICS (Q71-Q100)
  { id: 71, subject: "Physics", section: "Mechanics", q: "A ball is thrown vertically upward with velocity u. The time to reach maximum height is:", options: ["u/2g","2u/g","u/g","u²/2g"], ans: 2, exp: "At maximum height, v = 0. Using v = u − gt: 0 = u − gt → t = u/g. Maximum height h = u²/2g. Total time of flight = 2u/g (up + down). Speed when it returns to start = u (same magnitude, opposite direction). NCERT Class 11, Ch 3.", stars: 5 },
  { id: 72, subject: "Physics", section: "Mechanics", q: "A wheel of radius r rotates with angular velocity ω. The linear velocity of a point on the rim is:", options: ["ω/r","r/ω","ωr","ω²r"], ans: 2, exp: "Linear velocity v = ωr. Angular velocity ω (rad/s) relates to frequency: ω = 2πf = 2π/T. Centripetal acceleration: a = v²/r = ω²r (directed towards centre). Tangential acceleration = α × r (α = angular acceleration). NCERT Class 11, Ch 7.", stars: 5 },
  { id: 73, subject: "Physics", section: "Thermodynamics", q: "In an adiabatic process, which thermodynamic quantity remains constant?", options: ["Temperature","Pressure","Heat (Q = 0, no heat exchange with surroundings)","Volume"], ans: 2, exp: "Adiabatic: Q = 0 → ΔU = −W. No heat exchange (insulated). For adiabatic expansion: gas cools. PVγ = constant (γ = Cp/Cv). Isothermal: T = constant, PV = constant. Isobaric: P = constant. Isochoric (isovolumetric): V = constant, W = 0, ΔU = Q. NCERT Class 11, Ch 12.", stars: 5 },
  { id: 74, subject: "Physics", section: "Waves", q: "The Doppler effect in sound produces a change in:", options: ["Amplitude","Velocity of sound","Observed frequency (when source or observer moves)","Wavelength only, not frequency"], ans: 2, exp: "Doppler effect: f_obs = f_source × (v ± v_obs)/(v ∓ v_source). When source approaches: observed frequency increases (blue shift in light). When source recedes: frequency decreases (red shift). Used in: radar speed guns, medical ultrasound (blood flow velocity). NCERT Class 11, Ch 15.", stars: 5 },
  { id: 75, subject: "Physics", section: "Mechanics", q: "The work done by a force of 10 N along a displacement of 5 m at an angle of 60° to the force is:", options: ["50 J","25 J","43.3 J","10 J"], ans: 1, exp: "W = F·d·cosθ = 10 × 5 × cos60° = 10 × 5 × 0.5 = 25 J. Work is a scalar (dot product of F and d). If θ = 0°: W = Fd (maximum). If θ = 90°: W = 0 (perpendicular force does no work — e.g., centripetal force, normal force). If θ = 180°: W = −Fd (negative work). NCERT Class 11, Ch 6.", stars: 5 },
  { id: 76, subject: "Physics", section: "Thermodynamics", q: "For an ideal gas, internal energy U depends only on:", options: ["Pressure","Volume","Temperature (U = nCvT for ideal gas)","Pressure AND volume"], ans: 2, exp: "Ideal gas: intermolecular forces = 0, so potential energy = 0. Internal energy = kinetic energy only. U = nCvT (monoatomic gas: Cv = 3R/2; diatomic: Cv = 5R/2). Joule's experiment showed ΔU = 0 for free expansion of ideal gas (ΔT = 0). NCERT Class 11, Ch 12.", stars: 5 },
  { id: 77, subject: "Physics", section: "Mechanics", q: "The buoyant force (Archimedes' principle) on an object immersed in liquid equals:", options: ["Weight of the object","Mass of displaced liquid","Weight of liquid displaced by the object","Volume of the object × density of object"], ans: 2, exp: "Archimedes' principle: buoyant force = weight of fluid displaced = ρ_fluid × V_submerged × g. Object floats if buoyant force ≥ weight (ρ_object ≤ ρ_fluid). Applications: ships, submarines, hydrometers. NCERT Class 11, Ch 10.", stars: 4 },
  { id: 78, subject: "Physics", section: "Mechanics", q: "Bernoulli's theorem states that for streamline flow of an ideal fluid:", options: ["Pressure increases with velocity","P + ½ρv² + ρgh = constant (sum of pressure, kinetic and potential energy per unit volume)","Flow rate varies with cross-section","Viscosity remains constant"], ans: 1, exp: "Bernoulli's equation: P + ½ρv² + ρgh = constant. Conservation of energy for ideal (incompressible, non-viscous) fluid. Applications: lift on aeroplane wings, Venturi meter, atomiser (perfume spray), blood pressure measurement, Magnus effect (spinning ball). NCERT Class 11, Ch 10.", stars: 5 },
  { id: 79, subject: "Physics", section: "Thermodynamics", q: "Stefan-Boltzmann's law of radiation is expressed as:", options: ["E = σT²","E = σT⁴ (power radiated per unit area ∝ T⁴)","E = hf","E = σAT³"], ans: 1, exp: "Stefan-Boltzmann law: E = σT⁴, where σ = 5.67×10⁻⁸ W/m²/K⁴. Power radiated ∝ T⁴ (absolute temperature). Newton's law of cooling: rate of heat loss ∝ (T − T_surroundings). Wien's displacement law: λ_max × T = constant (2.898×10⁻³ m·K). NCERT Class 11, Ch 11.", stars: 5 },
  { id: 80, subject: "Physics", section: "Waves", q: "The quality (timbre) of a musical note depends on:", options: ["Frequency (pitch)","Amplitude (loudness)","Number and relative intensities of overtones (harmonics) present","Speed of sound"], ans: 2, exp: "Characteristics of sound: (1) Pitch — determined by frequency; (2) Loudness — determined by amplitude/intensity; (3) Quality/Timbre — determined by waveform (mixture of fundamental + harmonics). Same note on different instruments sounds different due to different overtone composition. NCERT Class 11, Ch 15.", stars: 4 },
  { id: 81, subject: "Physics", section: "Waves", q: "In resonance tube experiment, if length of air column for first resonance is L₁ = 20 cm, second resonance L₂ = ?", options: ["40 cm","60 cm","80 cm","30 cm"], ans: 1, exp: "Closed organ pipe: resonance at L = λ/4, 3λ/4, 5λ/4... First resonance: L₁ = λ/4. Second resonance: L₂ = 3λ/4 = 3L₁ = 3 × 20 = 60 cm. End correction: L₂ − L₁ = λ/2 → 60 − 20 = 40 cm → λ = 80 cm → v = fλ. NCERT Class 11, Ch 15.", stars: 5 },
  { id: 82, subject: "Physics", section: "Mechanics", q: "Poisson's ratio (σ) for a material relates to which mechanical properties?", options: ["Young's modulus to shear modulus","Lateral strain to longitudinal strain under tensile stress","Bulk modulus to compressibility","Stress to strain"], ans: 1, exp: "Poisson's ratio: σ = −(lateral strain)/(longitudinal strain). For most materials: 0 < σ < 0.5. Rubber: σ ≈ 0.5 (nearly incompressible). Metals: σ ≈ 0.25–0.35. A stretched wire becomes longer AND thinner (lateral contraction). NCERT Class 11, Ch 9.", stars: 4 },
  { id: 83, subject: "Physics", section: "Magnetism", q: "Gauss's law for magnetism states that the magnetic flux through any closed surface is:", options: ["Equal to µ₀ × enclosed magnetic charge","Always zero (∮B·dA = 0) — no magnetic monopoles exist","Equal to B × area","µ₀ × current"], ans: 1, exp: "Gauss's law for magnetism: ∮B·dA = 0. This is because magnetic monopoles do NOT exist — every magnetic field line that enters a closed surface must also exit. This is one of Maxwell's equations. Contrast: Gauss's law for electricity: ∮E·dA = Q_enclosed/ε₀. NCERT Class 12, Ch 5.", stars: 5 },
  { id: 84, subject: "Physics", section: "Electricity", q: "In a series RLC circuit at resonance, the impedance (Z) equals:", options: ["√(R² + (XL − XC)²)","R only (since XL = XC at resonance)","XL only","XC only"], ans: 1, exp: "Series RLC: Z = √(R² + (XL − XC)²). At resonance: XL = XC → Z = R (minimum impedance). Resonance frequency: f₀ = 1/(2π√LC). At resonance: current is maximum, power factor = 1, circuit behaves as purely resistive. Quality factor Q = (1/R)√(L/C). NCERT Class 12, Ch 7.", stars: 5 },
  { id: 85, subject: "Physics", section: "Electricity", q: "The motional EMF induced in a conductor of length l moving with velocity v perpendicular to magnetic field B is:", options: ["BIv","Blv","B²lv","Blv²"], ans: 1, exp: "Motional EMF: ε = Blv (when l, v, B all mutually perpendicular). Derived from Faraday's law: ε = −dΦ/dt = −d(Blx)/dt = −Blv (magnitude = Blv). This is the principle of an AC generator. Force on charge: F = qvB (Lorentz force drives charges). NCERT Class 12, Ch 6.", stars: 5 },
  { id: 86, subject: "Physics", section: "Modern Physics", q: "The range of electromagnetic spectrum in order of INCREASING frequency is:", options: ["Gamma rays → X-rays → UV → Visible → IR → Microwaves → Radio waves","Radio waves → Microwaves → IR → Visible → UV → X-rays → Gamma rays","Visible → IR → UV → Microwaves → Radio → X-rays → Gamma","IR → Visible → UV → X-rays → Gamma → Radio → Microwaves"], ans: 1, exp: "EM spectrum (increasing frequency / decreasing wavelength): Radio (λ ~1m+) → Microwaves (cm) → IR (µm) → Visible (400–700nm) → UV → X-rays (nm-Å) → Gamma rays (< 0.1Å). All travel at c = 3×10⁸ m/s in vacuum. NCERT Class 12, Ch 8.", stars: 5 },
  { id: 87, subject: "Physics", section: "Optics", q: "In a compound microscope, the objective lens forms a:", options: ["Virtual, erect, magnified image","Real, inverted, magnified image of the object","Real, erect, diminished image","Virtual, inverted, magnified image"], ans: 1, exp: "Compound microscope: objective (short focal length, high power) → forms real, inverted, magnified image (intermediate image) just inside focal length of eyepiece → eyepiece acts as simple magnifier → forms virtual, magnified, inverted final image. Total magnification = m_obj × m_eye. NCERT Class 12, Ch 9.", stars: 5 },
  { id: 88, subject: "Physics", section: "Optics", q: "In Young's double slit experiment, when one slit is covered, the intensity at the central point changes from I to:", options: ["Zero","I/4","I/2","2I"], ans: 1, exp: "In YDSE: when both slits open, central maximum intensity I = 4I₀ (constructive interference of two coherent sources each with amplitude a → 2a → intensity 4I₀). When one slit covered: intensity = I₀ = I/4. This demonstrates interference, not just superposition. NCERT Class 12, Ch 10.", stars: 5 },
  { id: 89, subject: "Physics", section: "Modern Physics", q: "The work function of sodium is 2.3 eV. The maximum wavelength of light that can cause photoelectric emission is approximately: (hc = 1240 eV·nm)", options: ["540 nm","340 nm","440 nm","640 nm"], ans: 0, exp: "Threshold wavelength: λ₀ = hc/φ = 1240/2.3 ≈ 539 nm ≈ 540 nm. This lies in green light range. Light with λ < 540 nm (higher frequency) will cause photoelectric emission. NCERT Class 12, Ch 11.", stars: 5 },
  { id: 90, subject: "Physics", section: "Modern Physics", q: "In a nuclear fission chain reaction, moderators (e.g., heavy water, graphite) are used to:", options: ["Absorb neutrons","Slow down (moderate) fast neutrons to thermal energies for efficient fission","Reflect neutrons","Initiate the chain reaction"], ans: 1, exp: "Chain reaction control in nuclear reactor: Moderator (D₂O, C-graphite, H₂O) — slows fast neutrons to thermal speeds (efficient fission of U-235). Control rods (boron, cadmium) — absorb excess neutrons, control reaction rate. Coolant (water, liquid sodium) — removes heat. NCERT Class 12, Ch 13.", stars: 5 },
  { id: 91, subject: "Physics", section: "Modern Physics", q: "The binding energy per nucleon is highest for:", options: ["Hydrogen (¹H)","Iron (⁵⁶Fe)","Uranium (²³⁵U)","Helium (⁴He)"], ans: 1, exp: "Binding energy per nucleon curve: peaks at ⁵⁶Fe (~8.8 MeV/nucleon) — most stable nucleus. For light nuclei (H, He): low BE/nucleon → fusion releases energy. For heavy nuclei (U, Th): slightly lower BE/nucleon → fission releases energy. Magic numbers (2,8,20,28,50,82,126) have extra stability. NCERT Class 12, Ch 13.", stars: 5 },
  { id: 92, subject: "Physics", section: "Electronics", q: "A Zener diode is mainly used as:", options: ["Rectifier","Voltage regulator (maintains constant output voltage)","Signal amplifier","Photodetector"], ans: 1, exp: "Zener diode: specially doped p-n junction for operation in reverse breakdown region. Maintains constant voltage (Zener voltage Vz) across it despite changes in input voltage or load current. Used in voltage regulators, overvoltage protection, reference voltage circuits. NCERT Class 12, Ch 14.", stars: 5 },
  { id: 93, subject: "Physics", section: "Electricity", q: "An electric charge placed inside a metallic (conducting) hollow sphere. What is the electric field inside the metallic shell itself?", options: ["Equal to field of charge","Zero (field inside conductor = 0)","Same as outside","Depends on position of charge"], ans: 1, exp: "Electrostatic shielding: electric field inside a conductor is zero (free electrons redistribute until E = 0 inside). Any charge resides on the outer surface. A charge inside a hollow sphere induces equal opposite charge on inner surface and equal charge on outer surface. Faraday cage: used to shield sensitive electronics. NCERT Class 12, Ch 1.", stars: 5 },
  { id: 94, subject: "Physics", section: "Electricity", q: "The Wheatstone bridge is most sensitive when all four resistances are:", options: ["Very large","Very small","Equal (or nearly equal)","Unequal"], ans: 2, exp: "Sensitivity of Wheatstone bridge is maximum when all four resistances P, Q, R, S are equal or nearly equal. In this condition, a small change in any resistance produces a large deflection in the galvanometer. At exact balance (P/Q = R/S), galvanometer reads zero. Metre bridge uses this principle. NCERT Class 12, Ch 3.", stars: 5 },
  { id: 95, subject: "Physics", section: "Magnetism", q: "What is the unit of magnetic moment of a current-carrying loop?", options: ["Tesla","Ampere per metre","A·m² (ampere × metre²)","Weber"], ans: 2, exp: "Magnetic moment of a current loop: m = NIA, where N = number of turns, I = current, A = area. Unit = A·m². Direction: right-hand rule (curl fingers along current → thumb points in direction of m). For an electron in orbit: m = evr/2. NCERT Class 12, Ch 5.", stars: 5 },
  { id: 96, subject: "Physics", section: "Optics", q: "Brewster's law: when light is incident at Brewster's angle (iB), the reflected and refracted rays are:", options: ["Parallel","Perpendicular to each other","At 45° to each other","Both completely polarised"], ans: 1, exp: "Brewster's law: tan(iB) = n (refractive index). At Brewster's angle: reflected ray is completely polarised (perpendicular to plane of incidence); refracted ray is partially polarised. Reflected + refracted rays are perpendicular (iB + r = 90°). Uses: anti-glare glasses, LCD screens, photography. NCERT Class 12, Ch 10.", stars: 5 },
  { id: 97, subject: "Physics", section: "Modern Physics", q: "A photon has energy 3 eV. Its wavelength is approximately: (hc = 1240 eV·nm)", options: ["413 nm","620 nm","310 nm","520 nm"], ans: 0, exp: "E = hc/λ → λ = hc/E = 1240 eV·nm / 3 eV ≈ 413 nm. This falls in the violet region of visible spectrum (400–430 nm). Remember: hc = 1240 eV·nm = 12400 eV·Å (useful shortcut for NEET numericals). NCERT Class 12, Ch 11.", stars: 5 },
  { id: 98, subject: "Physics", section: "Magnetism", q: "Two parallel wires carrying currents in the same direction:", options: ["Repel each other","Attract each other","Have no interaction","Rotate around each other"], ans: 1, exp: "Parallel wires: same direction → attract; opposite direction → repel. Force per unit length: F/L = µ₀I₁I₂/2πd. This defines the SI unit of current (Ampere): 1A is defined as the current that, in two parallel wires 1m apart, produces force of 2×10⁻⁷ N/m on each wire. NCERT Class 12, Ch 4.", stars: 5 },
  { id: 99, subject: "Physics", section: "Electronics", q: "In a p-n junction LED (Light Emitting Diode), light is emitted due to:", options: ["Reverse breakdown","Electron-hole recombination during forward bias releasing energy as photons","Zener effect","Photoelectric effect"], ans: 1, exp: "LED: forward biased p-n junction. Electrons from n-side and holes from p-side recombine at junction → energy released as photon. E_photon = E_g (band gap energy). Different semiconductors → different E_g → different colours. GaAs: IR LED; GaAsP: red; GaN: blue/white. NCERT Class 12, Ch 14.", stars: 5 },
  { id: 100, subject: "Physics", section: "Electricity", q: "The power factor of a purely inductive AC circuit is:", options: ["1","0.5","0 (current and voltage are 90° out of phase)","−1"], ans: 2, exp: "Power factor = cosφ. Purely inductive: voltage leads current by 90° → φ = 90° → cosφ = 0 → P = Vrms × Irms × 0 = 0 (no real power consumed). Purely resistive: φ = 0° → cosφ = 1 → P = Vrms × Irms (maximum power). Purely capacitive: φ = −90° → cosφ = 0. NCERT Class 12, Ch 7.", stars: 5 },
];

const OPTION_LABELS = ["A", "B", "C", "D"];

// NEW THEME: Warm Amber/Gold Academic theme
const theme = {
  bg: "#0f0900",
  bgGrad: "radial-gradient(ellipse at top left, #1a1000 0%, #0f0900 40%, #0a0500 100%)",
  surface: "rgba(255,180,0,0.04)",
  border: "rgba(255,180,0,0.1)",
  borderStrong: "rgba(255,180,0,0.25)",
  text: "#f5e6c0",
  textMuted: "#8a7040",
  textDim: "#5c4a20",
  gold: "#f5b800",
  goldLight: "#ffd54f",
  goldGlow: "rgba(245,184,0,0.15)",
  correct: "#4ade80",
  wrong: "#f87171",
  font: "'Georgia', serif",
};

const subjectColors = {
  Biology: { accent: "#4ade80", badge: "#4ade8020", border: "#4ade8040", label: "#86efac" },
  Chemistry: { accent: "#60a5fa", badge: "#60a5fa20", border: "#60a5fa40", label: "#93c5fd" },
  Physics: { accent: "#fb923c", badge: "#fb923c20", border: "#fb923c40", label: "#fdba74" },
};

export default function NEETApp() {
  const [examMode, setExamMode] = useState(null); // null, 1, 2
  const [phase, setPhase] = useState("home"); // home, exam, result, review
  const [current, setCurrent] = useState(0);
  const [answers, setAnswers] = useState({});
  const [revealed, setRevealed] = useState({});
  const [timeLeft, setTimeLeft] = useState(180 * 60);
  const [filter, setFilter] = useState("All");
  const timerRef = useRef(null);

  const questions = examMode === 1 ? exam1Questions : examMode === 2 ? exam2Questions : [];
  const totalQ = questions.length;
  const maxMarks = examMode === 1 ? 720 : 400;

  useEffect(() => {
    if (phase === "exam") {
      const duration = examMode === 1 ? 180 * 60 : 120 * 60;
      timerRef.current = setInterval(() => {
        setTimeLeft(t => {
          if (t <= 1) { clearInterval(timerRef.current); setPhase("result"); return 0; }
          return t - 1;
        });
      }, 1000);
    }
    return () => clearInterval(timerRef.current);
  }, [phase]);

  const formatTime = (s) => {
    const h = Math.floor(s / 3600);
    const m = Math.floor((s % 3600) / 60);
    const sec = s % 60;
    return `${h}:${String(m).padStart(2, "0")}:${String(sec).padStart(2, "0")}`;
  };

  const filteredQs = filter === "All" ? questions : questions.filter(q => q.subject === filter);
  const currentQ = filteredQs[current] || questions[0];

  const handleSelect = (idx) => {
    if (revealed[currentQ.id]) return;
    setAnswers(a => ({ ...a, [currentQ.id]: idx }));
    setRevealed(r => ({ ...r, [currentQ.id]: true }));
  };

  const calcScore = () => {
    let score = 0, correct = 0, wrong = 0, unattempted = 0;
    questions.forEach(q => {
      if (answers[q.id] === undefined) { unattempted++; }
      else if (answers[q.id] === q.ans) { correct++; score += 4; }
      else { wrong++; score -= 1; }
    });
    return { score, correct, wrong, unattempted };
  };

  const subjectStats = () => {
    const subjects = ["Biology", "Chemistry", "Physics"];
    return subjects.map(sub => {
      const qs = questions.filter(q => q.subject === sub);
      let correct = 0, wrong = 0, unattempted = 0;
      qs.forEach(q => {
        if (answers[q.id] === undefined) unattempted++;
        else if (answers[q.id] === q.ans) correct++;
        else wrong++;
      });
      return { subject: sub, correct, wrong, unattempted, total: qs.length };
    });
  };

  const resetAll = () => {
    setPhase("home"); setAnswers({}); setRevealed({}); setCurrent(0);
    setFilter("All"); setExamMode(null);
    setTimeLeft(180 * 60);
  };

  const startExam = (mode) => {
    setExamMode(mode);
    setAnswers({}); setRevealed({}); setCurrent(0); setFilter("All");
    setTimeLeft(mode === 1 ? 180 * 60 : 120 * 60);
    setPhase("exam");
  };

  // ─── HOME ───────────────────────────────────────────────────────────────────
  if (phase === "home") {
    return (
      <div style={{ fontFamily: theme.font, minHeight: "100vh", background: theme.bgGrad, color: theme.text, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", padding: "2rem 1rem", position: "relative", overflow: "hidden" }}>
        {/* Decorative rings */}
        <div style={{ position: "absolute", top: "50%", left: "50%", transform: "translate(-50%,-50%)", width: "800px", height: "800px", borderRadius: "50%", border: "1px solid rgba(245,184,0,0.04)", pointerEvents: "none" }} />
        <div style={{ position: "absolute", top: "50%", left: "50%", transform: "translate(-50%,-50%)", width: "560px", height: "560px", borderRadius: "50%", border: "1px solid rgba(245,184,0,0.06)", pointerEvents: "none" }} />
        <div style={{ position: "absolute", top: "50%", left: "50%", transform: "translate(-50%,-50%)", width: "340px", height: "340px", borderRadius: "50%", border: "1px solid rgba(245,184,0,0.08)", pointerEvents: "none" }} />
        <div style={{ position: "absolute", top: 0, left: 0, right: 0, height: "1px", background: `linear-gradient(90deg, transparent, ${theme.gold}40, transparent)` }} />

        <div style={{ textAlign: "center", maxWidth: "780px", zIndex: 1, width: "100%" }}>
          <div style={{ fontSize: "0.68rem", letterSpacing: "0.45em", textTransform: "uppercase", color: theme.textMuted, marginBottom: "1.5rem", fontFamily: "monospace" }}>National Eligibility cum Entrance Test · 2026</div>
          <h1 style={{ fontSize: "clamp(2.8rem, 7vw, 5rem)", fontWeight: "900", lineHeight: 1.05, margin: "0 0 0.3rem", background: `linear-gradient(135deg, ${theme.goldLight} 0%, ${theme.gold} 50%, #c8860a 100%)`, WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent", letterSpacing: "-0.02em" }}>NEET UG 2026</h1>
          <h2 style={{ fontSize: "clamp(0.9rem, 2vw, 1.15rem)", fontWeight: "400", color: theme.textMuted, letterSpacing: "0.2em", textTransform: "uppercase", marginBottom: "3rem" }}>Mock Test Series · Deep Syllabus Coverage</h2>

          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "1.25rem", marginBottom: "2.5rem" }}>
            {[
              { num: "01", title: "Mock Exam — Full Syllabus", subtitle: "180 Questions · 180 Mins · 720 Marks", tags: ["Biology 90Q", "Chemistry 45Q", "Physics 45Q"], color: subjectColors.Biology.accent, mode: 1, badge: "NEET Pattern" },
              { num: "02", title: "High-Frequency Questions", subtitle: "100 Questions · 120 Mins · 400 Marks", tags: ["Biology 40Q", "Chemistry 30Q", "Physics 30Q"], color: theme.gold, mode: 2, badge: "2020–2025 Repeated" },
            ].map(exam => (
              <div key={exam.num} style={{ background: theme.surface, border: `1px solid ${theme.border}`, borderRadius: "16px", padding: "1.75rem", textAlign: "left", position: "relative", overflow: "hidden", transition: "border-color 0.2s" }}
                onMouseOver={e => e.currentTarget.style.borderColor = exam.color + "50"}
                onMouseOut={e => e.currentTarget.style.borderColor = theme.border}
              >
                <div style={{ position: "absolute", top: "1rem", right: "1rem", background: `${exam.color}15`, border: `1px solid ${exam.color}30`, color: exam.color, fontSize: "0.6rem", fontWeight: "700", letterSpacing: "0.1em", textTransform: "uppercase", borderRadius: "4px", padding: "0.2rem 0.5rem" }}>{exam.badge}</div>
                <div style={{ fontSize: "3rem", fontWeight: "900", color: `${exam.color}30`, lineHeight: 1, fontFamily: "monospace", marginBottom: "0.5rem" }}>{exam.num}</div>
                <h3 style={{ margin: "0 0 0.3rem", fontSize: "1rem", fontWeight: "700", color: theme.text }}>{exam.title}</h3>
                <p style={{ margin: "0 0 1rem", fontSize: "0.78rem", color: theme.textMuted }}>{exam.subtitle}</p>
                <div style={{ display: "flex", gap: "0.4rem", flexWrap: "wrap", marginBottom: "1.25rem" }}>
                  {exam.tags.map(tag => (
                    <span key={tag} style={{ background: `${exam.color}12`, border: `1px solid ${exam.color}25`, color: exam.color, fontSize: "0.65rem", borderRadius: "4px", padding: "0.2rem 0.5rem" }}>{tag}</span>
                  ))}
                </div>
                <button onClick={() => startExam(exam.mode)} style={{ width: "100%", padding: "0.75rem", borderRadius: "10px", background: `${exam.color}18`, border: `1px solid ${exam.color}40`, color: exam.color, fontSize: "0.85rem", fontWeight: "700", cursor: "pointer", letterSpacing: "0.05em", textTransform: "uppercase", transition: "all 0.2s" }}
                  onMouseOver={e => { e.currentTarget.style.background = `${exam.color}30`; e.currentTarget.style.transform = "translateY(-1px)"; }}
                  onMouseOut={e => { e.currentTarget.style.background = `${exam.color}18`; e.currentTarget.style.transform = "translateY(0)"; }}
                >Begin →</button>
              </div>
            ))}
          </div>

          <div style={{ display: "grid", gridTemplateColumns: "repeat(3,1fr)", gap: "0.75rem", marginBottom: "1.5rem" }}>
            {[
              { label: "Correct", val: "+4", desc: "per question" },
              { label: "Wrong", val: "−1", desc: "negative marking" },
              { label: "Skip", val: "0", desc: "no penalty" },
            ].map(r => (
              <div key={r.label} style={{ background: theme.surface, border: `1px solid ${theme.border}`, borderRadius: "10px", padding: "0.85rem" }}>
                <div style={{ fontSize: "1.25rem", fontWeight: "800", color: theme.gold, fontFamily: "monospace" }}>{r.val}</div>
                <div style={{ fontSize: "0.7rem", color: theme.textMuted, textTransform: "uppercase", letterSpacing: "0.1em" }}>{r.label}</div>
                <div style={{ fontSize: "0.65rem", color: theme.textDim, marginTop: "0.15rem" }}>{r.desc}</div>
              </div>
            ))}
          </div>

          <div style={{ fontSize: "0.7rem", color: theme.textDim }}>Based on 6-year NEET trend analysis (2020–2025) · NCERT aligned · NTA exam pattern</div>
        </div>
      </div>
    );
  }

  // ─── RESULT ─────────────────────────────────────────────────────────────────
  if (phase === "result") {
    const { score, correct, wrong, unattempted } = calcScore();
    const stats = subjectStats();
    const pct = Math.round((score / maxMarks) * 100);
    const rank = score >= 600 ? "🏆 AIR < 1000 Range" : score >= 480 ? "🥇 Government MBBS" : score >= 360 ? "🥈 State Quota" : score >= 240 ? "🥉 Private Medical" : "📚 Needs More Practice";
    const col = score >= 480 ? theme.correct : score >= 240 ? theme.gold : theme.wrong;

    return (
      <div style={{ fontFamily: theme.font, minHeight: "100vh", background: theme.bgGrad, color: theme.text, padding: "2rem 1rem" }}>
        <div style={{ maxWidth: "820px", margin: "0 auto" }}>
          <div style={{ textAlign: "center", marginBottom: "2rem" }}>
            <div style={{ fontSize: "0.65rem", letterSpacing: "0.35em", color: theme.textMuted, textTransform: "uppercase", fontFamily: "monospace", marginBottom: "0.5rem" }}>NEET UG 2026 · {examMode === 1 ? "Mock Exam I" : "Mock Exam II"}</div>
            <h1 style={{ fontSize: "2.5rem", fontWeight: "900", margin: 0, color: theme.goldLight }}>Your Results</h1>
          </div>

          <div style={{ background: theme.surface, border: `1px solid ${theme.border}`, borderRadius: "20px", padding: "2rem", marginBottom: "1.25rem", textAlign: "center" }}>
            <div style={{ fontSize: "5.5rem", fontWeight: "900", lineHeight: 1, color: col, fontFamily: "monospace" }}>{score}</div>
            <div style={{ fontSize: "0.85rem", color: theme.textMuted, marginBottom: "0.4rem" }}>out of {maxMarks} marks</div>
            <div style={{ fontSize: "1.2rem", marginBottom: "1.5rem" }}>{rank}</div>
            <div style={{ width: "100%", height: "6px", background: "rgba(255,255,255,0.06)", borderRadius: "3px", overflow: "hidden", marginBottom: "0.4rem" }}>
              <div style={{ height: "100%", borderRadius: "3px", width: `${Math.max(0, Math.min(100, pct))}%`, background: `linear-gradient(90deg, ${col}, ${col}99)`, transition: "width 1.2s" }} />
            </div>
            <div style={{ fontSize: "0.75rem", color: theme.textMuted }}>{pct}% · {examMode === 1 ? "180 Questions" : "100 Questions"}</div>
          </div>

          <div style={{ display: "grid", gridTemplateColumns: "repeat(3,1fr)", gap: "0.75rem", marginBottom: "1.25rem" }}>
            {[
              { label: "Correct", value: correct, color: theme.correct, marks: `+${correct * 4}` },
              { label: "Wrong", value: wrong, color: theme.wrong, marks: `-${wrong}` },
              { label: "Skipped", value: unattempted, color: theme.textMuted, marks: "0" },
            ].map(s => (
              <div key={s.label} style={{ background: theme.surface, border: `1px solid ${s.color}25`, borderRadius: "12px", padding: "1.25rem", textAlign: "center" }}>
                <div style={{ fontSize: "2.2rem", fontWeight: "800", color: s.color, fontFamily: "monospace" }}>{s.value}</div>
                <div style={{ fontSize: "0.68rem", color: theme.textMuted, textTransform: "uppercase", letterSpacing: "0.1em", marginBottom: "0.2rem" }}>{s.label}</div>
                <div style={{ fontSize: "0.82rem", color: s.color, fontFamily: "monospace", fontWeight: "600" }}>{s.marks} marks</div>
              </div>
            ))}
          </div>

          <div style={{ background: theme.surface, border: `1px solid ${theme.border}`, borderRadius: "16px", padding: "1.5rem", marginBottom: "1.5rem" }}>
            <div style={{ fontSize: "0.65rem", letterSpacing: "0.2em", textTransform: "uppercase", color: theme.textMuted, marginBottom: "1rem" }}>Subject Performance</div>
            {stats.map(s => {
              const c = subjectColors[s.subject];
              const acc = s.total > 0 ? Math.round((s.correct / s.total) * 100) : 0;
              return (
                <div key={s.subject} style={{ marginBottom: "1.1rem" }}>
                  <div style={{ display: "flex", justifyContent: "space-between", marginBottom: "0.4rem" }}>
                    <span style={{ fontWeight: "600", color: c.accent, fontSize: "0.9rem" }}>{s.subject}</span>
                    <span style={{ fontSize: "0.75rem", color: theme.textMuted }}>{s.correct}/{s.total} · {acc}%</span>
                  </div>
                  <div style={{ width: "100%", height: "5px", background: "rgba(255,255,255,0.05)", borderRadius: "3px", overflow: "hidden" }}>
                    <div style={{ height: "100%", width: `${acc}%`, background: c.accent, borderRadius: "3px", transition: "width 1.2s" }} />
                  </div>
                  <div style={{ display: "flex", gap: "1rem", marginTop: "0.35rem", fontSize: "0.68rem", color: theme.textMuted }}>
                    <span style={{ color: theme.correct }}>✓ {s.correct}</span>
                    <span style={{ color: theme.wrong }}>✗ {s.wrong}</span>
                    <span>— {s.unattempted}</span>
                  </div>
                </div>
              );
            })}
          </div>

          <div style={{ display: "flex", gap: "0.75rem", justifyContent: "center" }}>
            <button onClick={resetAll} style={{ background: theme.surface, border: `1px solid ${theme.border}`, color: theme.text, padding: "0.75rem 1.75rem", borderRadius: "50px", cursor: "pointer", fontSize: "0.88rem", fontWeight: "600" }}>← Home</button>
            <button onClick={() => { setPhase("review"); setCurrent(0); setFilter("All"); }} style={{ background: `${theme.gold}20`, border: `1px solid ${theme.gold}50`, color: theme.gold, padding: "0.75rem 1.75rem", borderRadius: "50px", cursor: "pointer", fontSize: "0.88rem", fontWeight: "700" }}>Review Answers</button>
          </div>
        </div>
      </div>
    );
  }

  // ─── EXAM & REVIEW ──────────────────────────────────────────────────────────
  const isReview = phase === "review";
  const q = currentQ;
  const selectedAns = answers[q.id];
  const isAnswered = selectedAns !== undefined;
  const isCorrect = selectedAns === q.ans;
  const showExplanation = isReview || revealed[q.id];
  const col = subjectColors[q.subject];
  const attempted = Object.keys(answers).length;
  const { score } = calcScore();

  return (
    <div style={{ fontFamily: theme.font, minHeight: "100vh", background: theme.bgGrad, color: theme.text, display: "flex", flexDirection: "column" }}>
      {/* TOP LINE */}
      <div style={{ height: "2px", background: `linear-gradient(90deg, transparent, ${theme.gold}60, transparent)` }} />

      {/* HEADER */}
      <div style={{ position: "sticky", top: 0, zIndex: 10, background: "rgba(15,9,0,0.96)", backdropFilter: "blur(12px)", borderBottom: `1px solid ${theme.border}`, padding: "0.65rem 1rem" }}>
        <div style={{ maxWidth: "1100px", margin: "0 auto", display: "flex", alignItems: "center", gap: "0.75rem", flexWrap: "wrap" }}>
          <div style={{ fontSize: "0.65rem", fontWeight: "800", letterSpacing: "0.25em", color: theme.gold, textTransform: "uppercase", flexShrink: 0, fontFamily: "monospace" }}>NEET 2026 · {examMode === 1 ? "Paper I" : "Paper II"}</div>

          <div style={{ display: "flex", gap: "0.35rem", flexWrap: "wrap" }}>
            {["All", "Biology", "Chemistry", "Physics"].map(f => (
              <button key={f} onClick={() => { setFilter(f); setCurrent(0); }} style={{ padding: "0.25rem 0.65rem", borderRadius: "50px", border: `1px solid ${filter === f ? col.accent : theme.border}`, background: filter === f ? `${col.accent}18` : "transparent", color: filter === f ? col.accent : theme.textMuted, fontSize: "0.7rem", cursor: "pointer", fontWeight: filter === f ? "700" : "400", transition: "all 0.15s" }}>
                {f}
              </button>
            ))}
          </div>

          <div style={{ marginLeft: "auto", display: "flex", alignItems: "center", gap: "0.75rem", flexShrink: 0 }}>
            {!isReview && (
              <div style={{ fontFamily: "monospace", fontSize: "0.88rem", color: timeLeft < 600 ? theme.wrong : theme.gold, fontWeight: "800", minWidth: "5rem", textAlign: "right" }}>⏱ {formatTime(timeLeft)}</div>
            )}
            <div style={{ fontSize: "0.7rem", color: theme.textMuted, fontFamily: "monospace" }}>
              {attempted}/{totalQ} · <span style={{ color: score >= 0 ? theme.correct : theme.wrong, fontWeight: "700" }}>{score > 0 ? "+" : ""}{score}</span>
            </div>
            {!isReview && (
              <button onClick={() => { clearInterval(timerRef.current); setPhase("result"); }} style={{ padding: "0.35rem 0.9rem", borderRadius: "50px", background: `${theme.wrong}15`, border: `1px solid ${theme.wrong}35`, color: theme.wrong, fontSize: "0.7rem", cursor: "pointer", fontWeight: "700", letterSpacing: "0.05em" }}>Submit</button>
            )}
            {isReview && (
              <button onClick={() => setPhase("result")} style={{ padding: "0.35rem 0.9rem", borderRadius: "50px", background: `${theme.gold}15`, border: `1px solid ${theme.gold}35`, color: theme.gold, fontSize: "0.7rem", cursor: "pointer", fontWeight: "700" }}>← Results</button>
            )}
          </div>
        </div>
      </div>

      <div style={{ flex: 1, maxWidth: "1100px", margin: "0 auto", width: "100%", padding: "1.5rem 1rem", display: "grid", gridTemplateColumns: "1fr minmax(190px, 230px)", gap: "1.5rem", alignItems: "start" }}>
        {/* QUESTION PANEL */}
        <div>
          <div style={{ display: "flex", alignItems: "center", gap: "0.6rem", marginBottom: "1rem", flexWrap: "wrap" }}>
            <span style={{ background: `${col.accent}20`, color: col.accent, border: `1px solid ${col.accent}40`, borderRadius: "6px", padding: "0.2rem 0.6rem", fontSize: "0.7rem", fontWeight: "800", letterSpacing: "0.1em", textTransform: "uppercase" }}>Q {q.id}</span>
            <span style={{ background: theme.surface, color: theme.textMuted, border: `1px solid ${theme.border}`, borderRadius: "6px", padding: "0.2rem 0.6rem", fontSize: "0.7rem" }}>{q.subject}</span>
            <span style={{ background: theme.surface, color: theme.textMuted, border: `1px solid ${theme.border}`, borderRadius: "6px", padding: "0.2rem 0.6rem", fontSize: "0.7rem" }}>{q.section}</span>
            <span style={{ marginLeft: "auto", color: theme.gold, fontSize: "0.78rem" }}>{"★".repeat(q.stars)}</span>
          </div>

          <div style={{ background: theme.surface, border: `1px solid ${theme.border}`, borderRadius: "16px", padding: "1.5rem", marginBottom: "1rem" }}>
            <p style={{ margin: 0, fontSize: "1.05rem", lineHeight: 1.7, fontWeight: "500", color: theme.text }}>{q.q}</p>
          </div>

          <div style={{ display: "flex", flexDirection: "column", gap: "0.55rem", marginBottom: "1rem" }}>
            {q.options.map((opt, idx) => {
              let bg = theme.surface, borderColor = theme.border, textColor = theme.text, labelColor = theme.textMuted, badge = null;

              if (showExplanation) {
                if (idx === q.ans) {
                  bg = "rgba(74,222,128,0.08)"; borderColor = "rgba(74,222,128,0.4)"; textColor = "#d1fae5"; labelColor = theme.correct;
                  badge = <span style={{ marginLeft: "auto", background: "#4ade8018", color: theme.correct, border: "1px solid #4ade8040", borderRadius: "4px", padding: "0.1rem 0.5rem", fontSize: "0.62rem", fontWeight: "800", flexShrink: 0 }}>CORRECT</span>;
                } else if (isAnswered && idx === selectedAns && selectedAns !== q.ans) {
                  bg = "rgba(248,113,113,0.08)"; borderColor = "rgba(248,113,113,0.4)"; textColor = "#fee2e2"; labelColor = theme.wrong;
                  badge = <span style={{ marginLeft: "auto", background: "#f8717118", color: theme.wrong, border: "1px solid #f8717140", borderRadius: "4px", padding: "0.1rem 0.5rem", fontSize: "0.62rem", fontWeight: "800", flexShrink: 0 }}>WRONG</span>;
                }
              } else if (isAnswered && idx === selectedAns) {
                bg = `${col.accent}12`; borderColor = `${col.accent}45`; labelColor = col.accent;
              }

              return (
                <button key={idx} onClick={() => handleSelect(idx)} style={{ display: "flex", alignItems: "flex-start", gap: "0.75rem", padding: "0.9rem 1.1rem", borderRadius: "12px", background: bg, border: `1px solid ${borderColor}`, color: textColor, textAlign: "left", cursor: showExplanation ? "default" : "pointer", transition: "all 0.12s", fontSize: "0.93rem", lineHeight: 1.6, width: "100%" }}
                  onMouseOver={e => { if (!showExplanation && !isAnswered) { e.currentTarget.style.background = `${col.accent}0c`; e.currentTarget.style.borderColor = `${col.accent}35`; }}}
                  onMouseOut={e => { if (!showExplanation && !isAnswered) { e.currentTarget.style.background = bg; e.currentTarget.style.borderColor = theme.border; }}}
                >
                  <span style={{ minWidth: "1.5rem", height: "1.5rem", borderRadius: "50%", background: `${labelColor}18`, color: labelColor, display: "flex", alignItems: "center", justifyContent: "center", fontSize: "0.68rem", fontWeight: "800", flexShrink: 0, marginTop: "0.08rem" }}>{OPTION_LABELS[idx]}</span>
                  <span style={{ flex: 1 }}>{opt}</span>
                  {badge}
                </button>
              );
            })}
          </div>

          {showExplanation && (
            <div style={{ background: isCorrect || isReview ? "rgba(74,222,128,0.05)" : "rgba(248,113,113,0.05)", border: `1px solid ${isCorrect || isReview ? "rgba(74,222,128,0.2)" : "rgba(248,113,113,0.2)"}`, borderRadius: "12px", padding: "1.25rem" }}>
              {isAnswered && !isReview && (
                <div style={{ fontWeight: "700", marginBottom: "0.6rem", fontSize: "0.92rem", color: isCorrect ? theme.correct : theme.wrong }}>
                  {isCorrect ? "✅ Correct! +4 marks" : "❌ Incorrect. −1 mark"}
                </div>
              )}
              <div style={{ fontSize: "0.85rem", lineHeight: 1.75, color: theme.textMuted }}>
                <span style={{ fontWeight: "700", color: theme.text }}>Explanation: </span>{q.exp}
              </div>
            </div>
          )}

          <div style={{ display: "flex", gap: "0.75rem", marginTop: "1.25rem" }}>
            <button onClick={() => setCurrent(c => Math.max(0, c - 1))} disabled={current === 0} style={{ flex: 1, padding: "0.72rem", borderRadius: "10px", background: current === 0 ? "transparent" : theme.surface, border: `1px solid ${current === 0 ? theme.textDim : theme.border}`, color: current === 0 ? theme.textDim : theme.text, cursor: current === 0 ? "not-allowed" : "pointer", fontSize: "0.88rem", fontWeight: "600" }}>← Previous</button>
            <button onClick={() => setCurrent(c => Math.min(filteredQs.length - 1, c + 1))} disabled={current === filteredQs.length - 1} style={{ flex: 1, padding: "0.72rem", borderRadius: "10px", background: current === filteredQs.length - 1 ? "transparent" : `${col.accent}18`, border: `1px solid ${current === filteredQs.length - 1 ? theme.textDim : col.accent + "45"}`, color: current === filteredQs.length - 1 ? theme.textDim : col.accent, cursor: current === filteredQs.length - 1 ? "not-allowed" : "pointer", fontSize: "0.88rem", fontWeight: "600" }}>Next →</button>
          </div>
        </div>

        {/* SIDEBAR */}
        <div style={{ position: "sticky", top: "60px" }}>
          <div style={{ background: theme.surface, border: `1px solid ${theme.border}`, borderRadius: "14px", padding: "1rem" }}>
            <div style={{ fontSize: "0.62rem", textTransform: "uppercase", letterSpacing: "0.18em", color: theme.textMuted, marginBottom: "0.75rem" }}>Navigator</div>
            <div style={{ display: "grid", gridTemplateColumns: "repeat(6, 1fr)", gap: "4px", maxHeight: "480px", overflowY: "auto" }}>
              {filteredQs.map((fq, idx) => {
                const isAns = answers[fq.id] !== undefined;
                const isCor = answers[fq.id] === fq.ans;
                const isCur = idx === current;
                let bg, borderC;
                if (isCur) { bg = theme.gold; borderC = theme.gold; }
                else if (!isAns) { bg = theme.surface; borderC = theme.border; }
                else if (isCor) { bg = "rgba(74,222,128,0.15)"; borderC = "rgba(74,222,128,0.5)"; }
                else { bg = "rgba(248,113,113,0.15)"; borderC = "rgba(248,113,113,0.5)"; }
                return (
                  <button key={fq.id} onClick={() => setCurrent(idx)} style={{ aspectRatio: "1", borderRadius: "5px", background: bg, border: `1px solid ${borderC}`, color: isCur ? "#0f0900" : theme.text, fontSize: "0.58rem", fontWeight: isCur ? "800" : "500", cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", transition: "all 0.1s" }}>
                    {fq.id}
                  </button>
                );
              })}
            </div>
            <div style={{ marginTop: "0.75rem", borderTop: `1px solid ${theme.border}`, paddingTop: "0.75rem", display: "flex", flexDirection: "column", gap: "0.3rem", fontSize: "0.65rem", color: theme.textDim }}>
              <div style={{ display: "flex", gap: "0.4rem", alignItems: "center" }}><div style={{ width: "10px", height: "10px", borderRadius: "3px", background: "rgba(74,222,128,0.15)", border: "1px solid rgba(74,222,128,0.5)" }} /> Correct</div>
              <div style={{ display: "flex", gap: "0.4rem", alignItems: "center" }}><div style={{ width: "10px", height: "10px", borderRadius: "3px", background: "rgba(248,113,113,0.15)", border: "1px solid rgba(248,113,113,0.5)" }} /> Wrong</div>
              <div style={{ display: "flex", gap: "0.4rem", alignItems: "center" }}><div style={{ width: "10px", height: "10px", borderRadius: "3px", background: theme.surface, border: `1px solid ${theme.border}` }} /> Not Attempted</div>
            </div>
          </div>

          <div style={{ background: theme.surface, border: `1px solid ${theme.border}`, borderRadius: "14px", padding: "1rem", marginTop: "1rem" }}>
            <div style={{ fontSize: "0.62rem", textTransform: "uppercase", letterSpacing: "0.18em", color: theme.textMuted, marginBottom: "0.75rem" }}>Live Score</div>
            <div style={{ fontSize: "2.75rem", fontWeight: "900", color: score >= 0 ? theme.gold : theme.wrong, lineHeight: 1, textAlign: "center", fontFamily: "monospace" }}>{score}</div>
            <div style={{ textAlign: "center", fontSize: "0.72rem", color: theme.textMuted, marginBottom: "0.5rem" }}>/ {maxMarks} marks</div>
            <div style={{ fontSize: "0.68rem", color: theme.textDim, textAlign: "center" }}>{attempted} answered · {totalQ - attempted} remaining</div>
          </div>
        </div>
      </div>
    </div>
  );
}